        function randomFsbApp() {
            if (fsbQueue.length === 0) { fsbQueue = allFsbApps.map((_, i) => i); shuffleArray(fsbQueue); }
            const item = allFsbApps[fsbQueue.pop()]; fsbState.current = item;
            const fsbAuthor = document.getElementById("fsbAuthor");
            if (fsbAuthor) {
                fsbAuthor.textContent = randomFunnyNick(); 
                document.getElementById("fsbMeta").textContent = "Ожидает проверки УФСБ"; 
                document.getElementById("fsbText").textContent = item.text; 
                document.getElementById("fsbEvidence").textContent = "Документы: " + item.evidence;
            }
        }

        window.judgeFsb = function(action) {
            if (!state.started) { alert('Сначала нажми "Начать смену" в главном меню!'); return; }
            if (isSpamming() || !fsbState.current) return;
            const isCorrect = action === fsbState.current.type;
            fsbState.resolved++;
            if (action === 'approve') fsbState.approved++; else fsbState.rejected++;
            
            if (isCorrect) { 
                playSound('ok'); 
                pushLog(`✅ ФСБ: верный вердикт (${action})`); 
                addGameXp(10); 
                if (currentUser) shopState.fsbSpent = (shopState.fsbSpent || 0) - 5; 
            } 
            else { playSound('fail'); pushLog(`❌ ФСБ: ошибка в проверке!`); }
            
            document.getElementById("fsbResolvedValue").textContent = fsbState.resolved;
            document.getElementById("fsbApprovedValue").textContent = fsbState.approved;
            document.getElementById("fsbRejectedValue").textContent = fsbState.rejected;
            
            saveProgress(); randomFsbApp(); updateShopStats();
        };

