        async function loadGlobalShopAndRoulette() {
            const { data } = await supa.from('reports').select('*').in('email', ['SHOP_MOD', 'SHOP_AP', 'ROULETTE_MOD', 'ROULETTE_AP', 'CUSTOM_MOD_MSG', 'CUSTOM_AP_MSG', 'HIDDEN_CHECK', 'USER_ROLE', 'SHOP_OVERRIDE', 'GAME_XP']);
            customShopItems = []; customApShopItems = []; customModMessages = []; customSupQuestions = []; hiddenChecks = []; activeMods = []; activeAps = []; activeFsb = [];
            modRoulettePrizes = [...defaultModRoulettePrizes]; apRoulettePrizes = [...defaultApRoulettePrizes]; gameXpMod = 0; let priceOverrides = {};
            if (data) {
                data.forEach(row => {
                    if (row.email === 'SHOP_OVERRIDE') { priceOverrides[row.link] = Number(row.xp); }
                    else if (row.email === 'GAME_XP' && currentUser && row.link === currentUser.id) { gameXpMod += Number(row.xp); }
                    else if (row.email === 'SHOP_MOD') { customShopItems.push({ id: row.id, title: row.date, desc: row.status, price: Number(row.xp), icon: row.link }); } 
                    else if (row.email === 'SHOP_AP') { customApShopItems.push({ id: row.id, title: row.date, desc: row.status, price: Number(row.xp), icon: row.link }); } 
                    else if (row.email === 'ROULETTE_MOD') { const idx = modRoulettePrizes.findIndex(p => p.id === row.link); if(idx !== -1) { modRoulettePrizes[idx].text = row.date; modRoulettePrizes[idx].val = Number(row.xp); } } 
                    else if (row.email === 'ROULETTE_AP') { const idx = apRoulettePrizes.findIndex(p => p.id === row.link); if(idx !== -1) { apRoulettePrizes[idx].text = row.date; apRoulettePrizes[idx].val = Number(row.xp); } } 
                    else if (row.email === 'CUSTOM_MOD_MSG') { customModMessages.push({ type: row.status, text: row.date }); } 
                    else if (row.email === 'CUSTOM_AP_MSG') { customSupQuestions.push({ title: row.link, text: row.date, keywords: row.status.split(',').map(s => s.trim().toLowerCase()) }); } 
                    else if (row.email === 'HIDDEN_CHECK') { hiddenChecks.push({ id: row.id, userId: row.link, text: row.date, type: row.status }); }
                    else if (row.email === 'USER_ROLE') { 
                        if(row.status === 'moderator') activeMods.push(row.link); 
                        if(row.status === 'ap') activeAps.push(row.link); 
                        if(row.status === 'fsb') activeFsb.push(row.link); 
                    }
                });
            }
            shopItems = [...defaultShopItems, ...customShopItems].map(item => { if (priceOverrides[item.id]) item.price = priceOverrides[item.id]; return item; });
            apShopItems = [...defaultApShopItems, ...customApShopItems].map(item => { if (priceOverrides[item.id]) item.price = priceOverrides[item.id]; return item; });
            fsbShopItems = [...defaultFsbShopItems].map(item => { if (priceOverrides[item.id]) item.price = priceOverrides[item.id]; return item; });

            if (currentUser) {
                isModerator = activeMods.includes(currentUser.id) || adminEmails.includes(currentUser.email) || currentUser.email === creatorEmail || dynamicModLeaders.includes(currentUser.id);
                isAp = activeAps.includes(currentUser.id) || apLeadershipEmails.includes(currentUser.email) || currentUser.email === creatorEmail || dynamicApLeaders.includes(currentUser.id);
                isFsbUser = activeFsb.includes(currentUser.id) || adminEmails.includes(currentUser.email) || dynamicFsbLeaders.includes(currentUser.id) || currentUser.email === creatorEmail;
            }
            checkRolesAndAccess(); updateShopStats(); updateTicker();
        }

        async function updateTicker() {
            const banner = document.getElementById('infoBannerText'); if(!banner) return;
            const { data } = await supa.from('admin_logs').select('nickname, item_name').order('created_at', { ascending: false }).limit(1);
            if(data && data.length > 0) banner.innerHTML = `Последнее событие: Сотрудник <span>${data[0].nickname}</span> приобрел/выиграл: <span>${data[0].item_name}</span>!`;
            else banner.innerHTML = 'Добро пожаловать в тренажёр! Выполняйте квесты и зарабатывайте XP.';
        }
        setInterval(updateTicker, 60000);

