        document.querySelectorAll('.main-cat-btn').forEach(btn => {
            btn.addEventListener('click', () => {
                document.querySelectorAll('.main-cat-btn').forEach(b => b.classList.remove('active')); btn.classList.add('active');
                const subNavs = { general: document.getElementById('subNavGeneral'), moderation: document.getElementById('subNavModeration'), support: document.getElementById('subNavSupport'), organizations: document.getElementById('subNavOrganizations') };
                Object.values(subNavs).forEach(nav => { if(nav) nav.style.display = 'none'; });
                const cat = btn.dataset.cat; if(subNavs[cat]) { subNavs[cat].style.display = 'flex'; const firstBtn = subNavs[cat].querySelector('.mode-btn'); if(firstBtn) firstBtn.click(); }
            });
        });

        document.querySelectorAll(".mode-btn").forEach(btn => { btn.addEventListener("click", () => switchMode(btn.dataset.mode, btn)); });

        function randomFunnyNick() { 
            const funnyLeft = ["Мелстройность", "Смешнявка", "Макенза", "Сраупен", "бурмалда", "Рассыльщик", "ПолитТоксик", "РелигБаттл", "Дед_с_Клавой"], funnyRight = ["из_Тамбова", "без_микрофона", "на_ГлОбАнЕ", "в_муте", "с_баном", "тянет_конфу", "обижен", "любит_капс", "ищет_баги"];
            return `${funnyLeft[Math.floor(Math.random() * funnyLeft.length)]}_${funnyRight[Math.floor(Math.random() * funnyRight.length)]}#${Math.floor(1000 + Math.random() * 8999)}`;
        }
        function shuffleArray(array) { for (let i = array.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [array[i], array[j]] = [array[j], array[i]]; } }
        function initials(name) { return name.split(/[#_\s]+/).filter(Boolean).slice(0, 2).map(part => part[0]).join("").toUpperCase(); }
        
        function getTrainingBalance() { return Math.floor(Number(state.correct) / 10) * 15; }
        function getRealBalance() { return Math.max(0, Number(state.reportXp || 0) - Number(shopState.spent || 0)); }
        function getGameNetBalance() { return gameXpMod; }

        function availableXp() { 
            let real = getRealBalance(), game = getTrainingBalance() + getGameNetBalance();
            if (game < 0) { real += game; game = 0; }
            return Math.max(0, real + game); 
        }

        function availablePts() { return Math.max(0, Math.floor(Number(supportState.correct) / 10) * 15 - Number(shopState.apSpent || 0)); }
        function getFsbPoints() { return Math.max(0, Math.floor(Number(fsbState.approved + fsbState.rejected) / 5) * 10 - Number(shopState.fsbSpent || 0)); }

        async function addGameXp(amount) {
            if (!currentUser) return; gameXpMod += amount;
            await supa.from('reports').insert([{ id: 'gxp_' + Date.now() + Math.random(), email: 'GAME_XP', link: currentUser.id, xp: amount, status: 'mod' }]);
        }

        let lastActionTime = 0, spamWarnings = 0, spamTimerInterval = null;
        function isSpamming() {
            const now = Date.now(), blockUntil = localStorage.getItem('spam_block_until');
            if (blockUntil && now < blockUntil) return true;
            if (now - lastActionTime < 1000) {
                spamWarnings++;
                if (spamWarnings >= 3) {
                    localStorage.setItem('spam_block_until', now + 60000);
                    showSpamModalWithTimer(); spamWarnings = 0; return true;
                }
            } else { spamWarnings = Math.max(0, spamWarnings - 1); }
            lastActionTime = now; return false;
        }

        function showSpamModalWithTimer() {
            const blockUntil = localStorage.getItem('spam_block_until'); if (!blockUntil) return;
            const modal = document.getElementById('spamModal'), closeBtn = document.getElementById('closeSpamModal');
            modal.style.display = 'flex'; closeBtn.disabled = true; closeBtn.style.opacity = '0.5'; closeBtn.style.cursor = 'not-allowed';
            let timeLeft = Math.ceil((blockUntil - Date.now()) / 1000); if (timeLeft < 0) timeLeft = 60;
            closeBtn.textContent = `Блокировка: ${timeLeft} сек...`; clearInterval(spamTimerInterval);
            spamTimerInterval = setInterval(() => {
                timeLeft--;
                if (timeLeft <= 0) { clearInterval(spamTimerInterval); localStorage.removeItem('spam_block_until'); closeBtn.disabled = false; closeBtn.style.opacity = '1'; closeBtn.style.cursor = 'pointer'; closeBtn.textContent = 'Я понял, больше не буду'; } 
                else closeBtn.textContent = `Блокировка: ${timeLeft} сек...`;
            }, 1000);
        }

        function pushLog(text) { state.log.unshift(text); state.log = state.log.slice(0, 50); renderLogs(); }
        function renderLogs() {
            const logList = document.getElementById("logList"); if (!logList) return;
            logList.innerHTML = state.log.length > 0 ? state.log.map(item => `<div class="log-item">${item}</div>`).join("") : '<div class="log-item">Пока пусто. Нажми «Начать смену».</div>';
        }

        function startGame() {
            state.started = true;
            const sb = document.getElementById('startBtn'); if(sb) sb.disabled = true;
            randomMessage();
            updateModStats(); updateSupportStats(); updateComplaintStats(); document.getElementById("game").scrollIntoView({ behavior: "smooth", block: "start" });
        }

        function resetGame() {
            state.started = false;
            const sb = document.getElementById('startBtn'); if(sb) sb.disabled = false;
            document.getElementById("messageText").textContent = "Пока сообщений нет. Нажми «Начать смену».";
            pushLog('Смена сброшена.'); updateModStats(); updateSupportStats(); updateComplaintStats();
        }

        async function checkAndApplyHiddenChecks() {
            if(!currentUser) return null;
            const hcIndex = hiddenChecks.findIndex(hc => hc.userId === currentUser.id);
            if(hcIndex !== -1) {
                const check = hiddenChecks[hcIndex]; await supa.from('reports').delete().eq('id', check.id); hiddenChecks.splice(hcIndex, 1);
                return { type: check.type, text: check.text, user: "Тайный_Покупатель" };
            } return null;
        }

        async function randomMessage() {
            let hc = await checkAndApplyHiddenChecks();
            if(hc) {
                state.current = hc; document.getElementById("authorName").textContent = hc.user; document.getElementById("authorMeta").textContent = "Ожидает проверки"; document.getElementById("messageText").textContent = hc.text; document.getElementById("avatarBox").textContent = initials(hc.user); return;
            }
            let combinedModMessages = [...baseModMessages, ...customModMessages];
            if (modQueue.length === 0) { modQueue = combinedModMessages.map((_, i) => i); shuffleArray(modQueue); }
            const item = combinedModMessages[modQueue.pop()], user = randomFunnyNick();
            state.current = { ...item, user };
            document.getElementById("authorName").textContent = user; document.getElementById("authorMeta").textContent = "Ожидает проверки"; document.getElementById("messageText").textContent = item.text; document.getElementById("avatarBox").textContent = initials(user);
        }

        function randomComplaint() {
            if (compQueue.length === 0) { compQueue = allComplaints.map((_, i) => i); shuffleArray(compQueue); }
            const item = allComplaints[compQueue.pop()]; complaintState.current = item;
            document.getElementById("compAuthor").textContent = randomFunnyNick(); document.getElementById("compMeta").textContent = "Ожидает вердикта"; document.getElementById("compText").textContent = item.text; document.getElementById("compEvidence").textContent = "Доказательства: " + item.evidence;
        }

        function taNextMsg() {
            let combinedModMessages = [...baseModMessages, ...customModMessages];
            if (taQueue.length === 0) { taQueue = combinedModMessages.map((_, i) => i); shuffleArray(taQueue); }
            const item = combinedModMessages[taQueue.pop()], user = randomFunnyNick(); taState.current = { ...item, user };
            document.getElementById("taAuthorName").textContent = user; document.getElementById("taMessageText").textContent = item.text; document.getElementById("taAvatar").textContent = initials(user);
        }

        function updateTaUI() {
            const m = Math.floor(Math.max(0, taTimeLeft) / 60), s = Math.max(0, taTimeLeft) % 60;
            document.getElementById('taTimer').textContent = `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
            if(taTimeLeft <= 10) document.getElementById('taTimer').classList.add('danger'); else document.getElementById('taTimer').classList.remove('danger');
            document.getElementById('taScore').textContent = taState.score; document.getElementById('taMistakes').textContent = taState.mistakes;
        }

        async function endTaGame() {
            clearInterval(taTimerInt); document.getElementById('taTimer').textContent = "00:00";
            const reward = Math.floor(taState.score * 2);
            if(reward > 0) { alert(`Время вышло! Ваш счет: ${taState.score}, Ошибок: ${taState.mistakes}\nВы заработали +${reward} XP!`); await addGameXp(reward); updateShopStats(); updateModStats(); await saveProgress(); } 
            else { alert(`Время вышло! Увы, вы не заработали очков.`); }
            document.getElementById('taStartScreen').style.display = 'block'; document.getElementById('taGameScreen').style.display = 'none';
        }

        function renderProfileData() {
            const nameEl = document.getElementById('profileName');
            let baseName = currentNickname || (currentUser ? currentUser.email : "Неизвестно");
            if (activeCosmetics.crown) { baseName = "👑 " + baseName; } nameEl.textContent = baseName;
            if (activeCosmetics.color) { nameEl.style.background = "linear-gradient(90deg, #ff6b88, #ffbf47, #52c77b, #6c8cff, #a26cff)"; nameEl.style.webkitBackgroundClip = "text"; nameEl.style.webkitTextFillColor = "transparent"; nameEl.style.display = "inline-block"; } 
            else { nameEl.style.background = "none"; nameEl.style.webkitTextFillColor = "initial"; nameEl.style.color = "#fff"; }
            const btnCrown = document.getElementById('equipCrownBtn'); if (btnCrown) btnCrown.textContent = activeCosmetics.crown ? "Снять" : "Надеть";
            const btnColor = document.getElementById('equipColorBtn'); if (btnColor) btnColor.textContent = activeCosmetics.color ? "Снять" : "Надеть";
            if(currentUser && currentNickname) { document.getElementById('profileAvatar').textContent = initials(currentNickname); }
            document.getElementById('profileXp').textContent = availableXp(); document.getElementById('profileRealXp').textContent = getRealBalance(); document.getElementById('profilePts').textContent = availablePts();
        }

        function updateModStats() {
            normalizeModTrainerCounters();
            const xp = availableXp();
            document.getElementById("resolvedValue").textContent = state.resolved; document.getElementById("correctValue").textContent = state.correct; document.getElementById("mistakeValue").textContent = state.mistakes; document.getElementById("xpValue").textContent = xp;
            document.getElementById("xpFill").style.width = (Math.min(1, (state.correct % 10 || (state.correct ? 10 : 0)) / 10) * 100) + "%";
            document.getElementById("resultBanner").firstElementChild.innerHTML = `<strong>${!state.started ? "Результат: смена ещё не начата" : "Результат: смена в процессе"}</strong>`;
            document.getElementById("resultHint").textContent = !state.started ? "Нажми «Начать смену», чтобы получить первое сообщение." : `Сейчас доступно ${xp} XP.`;
            saveModTrainerCountersLocal();
            updateShopStats(); renderQuests();
        }
        
        function updateSupportStats() {
            const pts = availablePts();
            document.getElementById("supportResolvedValue").textContent = supportState.resolved; document.getElementById("supportCorrectValue").textContent = supportState.correct; document.getElementById("supportMistakeValue").textContent = supportState.mistakes; document.getElementById("supportXpValue").textContent = pts;
            document.getElementById("supportXpFill").style.width = (Math.min(1, (supportState.correct % 10 || (supportState.correct ? 10 : 0)) / 10) * 100) + "%";
            document.getElementById("supportBannerHint").textContent = `Общий баланс: ${pts} Баллов.`;
            updateShopStats(); renderQuests();
        }
        
        function updateComplaintStats() {
            document.getElementById("compResolvedValue").textContent = complaintState.resolved; document.getElementById("compCorrectValue").textContent = complaintState.correct; document.getElementById("compMistakeValue").textContent = complaintState.mistakes; document.getElementById("compXpValue").textContent = availableXp(); renderQuests();
        }
        
        function updateShopStats() {
            let real = getRealBalance(), gameBal = getTrainingBalance() + getGameNetBalance();
            if (gameBal < 0) { real += gameBal; gameBal = 0; }
            if(document.getElementById('shopGameXp')) document.getElementById('shopGameXp').textContent = Math.max(0, gameBal);
            if(document.getElementById('shopRealXp')) document.getElementById('shopRealXp').textContent = Math.max(0, real);
            if(document.getElementById('apShopTotalPts')) document.getElementById('apShopTotalPts').textContent = availablePts();
            
            if(document.getElementById('fsbShopTotalPts')) document.getElementById('fsbShopTotalPts').textContent = getFsbPoints();
            
            if(document.getElementById('apShopSpentPts')) {
                const actualSpent = Number(shopState.apSpent) || 0;
                document.getElementById('apShopSpentPts').textContent = actualSpent < 0 ? `В плюсе: ${Math.abs(actualSpent)}` : actualSpent;
            }
            renderShopItems(); renderApShopItems(); renderFsbShopItems();
        }

        function renderShopItems() {
            const container = document.getElementById('shopItemsContainer'); if(!container) return;
            const totalXp = availableXp(), realXp = getRealBalance();
            container.innerHTML = shopItems.map(item => {
                const isGame = !!item.action, canAfford = isGame ? (totalXp >= item.price) : (realXp >= item.price), errorReason = isGame ? "Не хватает XP" : "Нужен XP с Отчетов";
                return `<div class="shop-card"> <div style="display:flex; justify-content:space-between; align-items:start;"><h3>${item.icon} ${item.title}</h3><div class="shop-price">${item.price} XP</div></div> <p>${item.desc}</p> <button class="shop-buy-btn" ${!canAfford ? 'disabled' : ''} onclick="buyItem('${item.id}', ${item.price}, '${item.action || ''}')">${canAfford ? (isGame ? 'Играть' : 'Купить') : errorReason}</button> </div>`;
            }).join('');
        }
        
        function renderApShopItems() {
            const container = document.getElementById('apShopItemsContainer'); if(!container) return;
            const currentPts = availablePts();
            container.innerHTML = apShopItems.map(item => {
                const canAfford = currentPts >= item.price;
                return `<div class="shop-card ap-shop-card"> <div style="display:flex; justify-content:space-between; align-items:start;"><h3>${item.icon} ${item.title}</h3><div class="shop-price ap-shop-price">${item.price} Баллов</div></div> <p>${item.desc}</p> <button class="shop-buy-btn ap-shop-buy-btn" ${!canAfford ? 'disabled' : ''} onclick="buyApItem('${item.id}', ${item.price}, '${item.action || ''}')">${canAfford ? 'Купить' : 'Не хватает Баллов'}</button> </div>`;
            }).join('');
        }

        function renderFsbShopItems() {
            const container = document.getElementById('fsbShopItemsContainer'); if(!container) return;
            container.innerHTML = ''; const currentPts = getFsbPoints();
            fsbShopItems.forEach(item => {
                const canAfford = currentPts >= item.price;
                container.innerHTML += `<div class="shop-card" style="border-color: rgba(108, 140, 255, 0.4);">
                    <div style="display:flex; justify-content:space-between; align-items:start;"><h3 style="color:#6c8cff;">${item.icon} ${item.title}</h3><div class="shop-price" style="color:#6c8cff; border-color:#6c8cff; background:rgba(108,140,255,0.1);">${item.price} Баллов</div></div>
                    <p>${item.desc}</p>
                    <button class="shop-buy-btn" style="background: linear-gradient(135deg, #6c8cff, #4a6fe3); color:#fff;" ${!canAfford ? 'disabled' : ''} onclick="buyFsbItem('${item.id}', ${item.price})">${canAfford ? 'Купить' : 'Не хватает Баллов'}</button>
                </div>`;
            });
        }

        async function logPurchase(itemName, isAutoLog, isAp = false, cost = 0) {
            if (!currentUser) return;
            await supa.from('admin_logs').insert([{ user_email: currentUser.email, nickname: currentNickname || currentUser.email, item_name: itemName, cost: cost, type: isAp ? 'ap_shop' : 'mod_shop', status: isAutoLog ? 'Автоматически зачислено' : 'Ожидает выдачи' }]);
            updateTicker();
        }

        window.buyItem = async function(id, price, action) {
            const isGame = !!action;
            let currencyType = 'real';
            let bal = getRealBalance();

            if (isGame) {
                currencyType = await chooseCurrencyForOperation(price, 'Мини-игра');
                if (!currencyType) return;
                bal = currencyType === 'game' ? (getTrainingBalance() + getGameNetBalance()) : getRealBalance();
            }

            if (bal >= price) {
                if (currencyType === 'game') { await addGameXp(-price); } 
                else { shopState.spent += price; }
                
                playSound('ok'); updateShopStats(); await saveProgress();
                window.currentGameCurrency = currencyType;
                
                if (action === 'mod_roulette') { openFortune(false); return; }
                if (action === 'mod_coin') { openCoinGame(); return; }
                if (action === 'mod_safes') { openSafesGame(); return; }
                if (action === 'mod_jw') { openJwQuiz(); return; }

                if (isGame) {
                    const modal = document.getElementById('genericGameModal');
                    const overlay = document.getElementById('ggStartOverlay');
                    const startBtn = document.getElementById('ggStartActionBtn');
                    const item = shopItems.find(i => i.id === id);

                    document.getElementById('ggTitle').textContent = item.title;
                    document.getElementById('ggStartTitle').textContent = item.title;
                    document.getElementById('ggStartBetText').textContent = `Ставка: ${price} ${currencyType === 'real'?'Реальных':'Игровых'} XP`;
                    document.getElementById('ggResult').textContent = '';
                    document.getElementById('closeGgBtn').style.display = 'none';

                    const areas = ['ggRps', 'ggSlots', 'ggTiming', 'ggRocket', 'ggCases', 'ggDice', 'ggMines', 'ggHiLo', 'ggWheelX', 'ggShells'];
                    areas.forEach(a => { const el = document.getElementById(a); if(el) el.style.display = 'none'; });

                    if(overlay) overlay.style.display = 'flex';
                    modal.style.display = 'flex';

                    if(startBtn) {
                        startBtn.onclick = () => {
                            if(overlay) overlay.style.display = 'none';
                            if (action === 'mod_crash') openRocketGame(price);
                            else if (action === 'mod_cases') openCasesGame(price);
                            else if (action === 'mod_dice') openDiceGame(price);
                            else if (action === 'mod_mines') openMinesGame(price);
                            else if (action === 'mod_hilo') openHiLoGame(price);
                            else if (action === 'mod_wheelx') openWheelXGame(price);
                            else if (action === 'mod_shells') openShellsGame(price);
                            else window.playGenericGame(id, price);
                        };
                    }
                } else { 
                    const item = shopItems.find(i => i.id === id); 
                    await logPurchase(`Покупка: ${item.title}`, false, false, price); 
                    alert(`Куплено: ${item.title}. Заявка отправлена руководству!`); 
                }
            } else { playSound('fail'); alert("Не хватает средств!"); }
        };
        
        window.buyApItem = async function(id, price, action) {
            if (availablePts() >= price) {
                shopState.apSpent += Math.abs(price); 
                playSound('ok'); updateShopStats(); await saveProgress();
                if (action === 'ap_roulette') openFortune(true);
                else { const item = apShopItems.find(i => i.id === id); await logPurchase(`Покупка: ${item.title}`, false, true, price); alert(`Куплено: ${item.title}. Заявка отправлена руководству АП!`); }
            } else playSound('fail');
        };

        window.buyFsbItem = async function(id, price) {
            if (getFsbPoints() >= price) {
                shopState.fsbSpent = (shopState.fsbSpent || 0) + price;
                playSound('ok'); updateShopStats(); await saveProgress();
                const item = fsbShopItems.find(i => i.id === id);
                await logPurchase(`Покупка ФСБ: ${item.title}`, false, false, price); 
                alert(`Успешно куплено: ${item.title}. Ожидайте выдачи от Лидера/Следящего ФСБ.`);
            } else playSound('fail');
        };

        // ЛОГИКА НОВЫХ ИГР
        let rocketInt = null;
        function openRocketGame(bet) {
            document.getElementById('ggRocket').style.display = 'flex';
            const multEl = document.getElementById('rocketMultiplier'), emojiEl = document.getElementById('rocketEmoji'), cashBtn = document.getElementById('ggRocketCashoutBtn') || document.getElementById('ggCrashCashoutBtn');
            cashBtn.disabled = false; cashBtn.textContent = "Забрать (Cashout)"; cashBtn.style.background = "var(--color-success)";
            
            let mult = 1.00; const crashPoint = Math.random() < 0.05 ? 1.00 : (1.00 + Math.pow(Math.random(), 3) * 5.00); let crashed = false; let bottomPos = 10;
            
            clearInterval(rocketInt);
            rocketInt = setInterval(async () => {
                mult += 0.01 + (mult * 0.005); bottomPos += 1;
                if (mult >= crashPoint) {
                    mult = crashPoint; crashed = true; clearInterval(rocketInt);
                    multEl.textContent = "CRASHED @ " + mult.toFixed(2) + "x"; multEl.style.color = "var(--color-error)"; emojiEl.textContent = '💥';
                    cashBtn.disabled = true; finishInteractiveGame(0, "Вы проиграли ставку!");
                } else {
                    multEl.textContent = mult.toFixed(2) + "x"; multEl.style.color = "#fff"; if(bottomPos < 200) emojiEl.style.bottom = bottomPos + "px";
                }
            }, 50);
            
            cashBtn.onclick = async () => {
                if (crashed) return; clearInterval(rocketInt); cashBtn.disabled = true;
                const winAmount = Math.floor(bet * mult); 
                multEl.textContent = "ЗАБРАЛ " + mult.toFixed(2) + "x"; multEl.style.color = "var(--color-success)";
                finishInteractiveGame(winAmount, `Успех! Выигрыш: ${winAmount} XP`);
            };
        }

        function openDiceGame(bet) {
            document.getElementById('ggDice').style.display = 'flex';
            const btn = document.getElementById('ggDiceBtn'), pBox = document.getElementById('dicePlayer'), dBox = document.getElementById('diceDealer');
            pBox.textContent = '?'; dBox.textContent = '?'; btn.disabled = false;
            btn.onclick = () => {
                btn.disabled = true; let rolls = 0;
                const anim = setInterval(() => {
                    pBox.textContent = Math.floor(Math.random() * 6) + 1; dBox.textContent = Math.floor(Math.random() * 6) + 1; rolls++;
                    if(rolls > 15) {
                        clearInterval(anim); const pVal = parseInt(pBox.textContent), dVal = parseInt(dBox.textContent);
                        if(pVal > dVal) finishInteractiveGame(bet*2, `Вы победили! Выпало ${pVal} против ${dVal}.`);
                        else if (pVal === dVal) finishInteractiveGame(bet, `Ничья! Возврат ставки.`);
                        else finishInteractiveGame(0, `Вы проиграли! Дилер выбросил ${dVal}.`);
                    }
                }, 50);
            };
        }

        function openMinesGame(bet) {
            let found = 0; document.getElementById('ggMines').style.display = 'flex'; document.getElementById('minesProgress').textContent = 'Найдено: 0 / 3';
            const grid = document.getElementById('minesGrid'); grid.innerHTML = '';
            let arr = Array(9).fill('safe'); let bPlaced = 0;
            while(bPlaced < 2) { let idx = Math.floor(Math.random() * 9); if(arr[idx] !== 'bomb') { arr[idx] = 'bomb'; bPlaced++; } }
            for(let i=0; i<9; i++) {
                const cell = document.createElement('div'); cell.className = 'mine-cell'; cell.style.background = 'rgba(255,255,255,0.1)'; cell.style.border = '2px solid rgba(255,255,255,0.2)'; cell.style.borderRadius = '12px'; cell.style.height = '75px'; cell.style.display = 'flex'; cell.style.alignItems = 'center'; cell.style.justifyContent = 'center'; cell.style.fontSize = '2rem'; cell.style.cursor = 'pointer'; cell.style.boxShadow = 'inset 0 0 10px rgba(0,0,0,0.5)';
                cell.onclick = () => {
                    if(cell.classList.contains('revealed')) return; cell.classList.add('revealed'); cell.style.cursor = 'default';
                    if(arr[i] === 'bomb') {
                        cell.style.background = 'rgba(255,107,136,0.4)'; cell.style.borderColor = '#ff6b88'; cell.textContent = '💣'; grid.style.pointerEvents = 'none';
                        finishInteractiveGame(0, `Взрыв! Вы нарвались на мину.`);
                    } else {
                        cell.style.background = 'rgba(82,199,123,0.2)'; cell.style.borderColor = '#52c77b'; cell.textContent = '💎'; found++; document.getElementById('minesProgress').textContent = `Найдено: ${found} / 3`;
                        if(found === 3) { grid.style.pointerEvents = 'none'; finishInteractiveGame(bet*2, `Победа! Вы нашли 3 алмаза!`); }
                    }
                }; grid.appendChild(cell);
            }
        }

        function openHiLoGame(bet) {
            document.getElementById('ggHiLo').style.display = 'flex';
            const currentBox = document.getElementById('hiloCurrent'), btnH = document.getElementById('btnHiLoHigh'), btnL = document.getElementById('btnHiLoLow');
            let currentNum = Math.floor(Math.random() * 80) + 10; currentBox.textContent = currentNum; btnH.disabled = false; btnL.disabled = false;
            const guess = (high) => {
                btnH.disabled = true; btnL.disabled = true;
                let nextNum = Math.floor(Math.random() * 100) + 1; while(nextNum === currentNum) nextNum = Math.floor(Math.random() * 100) + 1;
                let rolls = 0; const anim = setInterval(() => {
                    currentBox.textContent = Math.floor(Math.random() * 100) + 1; rolls++;
                    if(rolls > 15) {
                        clearInterval(anim); currentBox.textContent = nextNum; const isHigh = nextNum > currentNum;
                        if((high && isHigh) || (!high && !isHigh)) finishInteractiveGame(bet*2, `Верно! Выпало ${nextNum}.`); else finishInteractiveGame(0, `Неверно. Выпало ${nextNum}.`);
                    }
                }, 50);
            };
            btnH.onclick = () => guess(true); btnL.onclick = () => guess(false);
        }

        function openWheelXGame(bet) {
            document.getElementById('ggWheelX').style.display = 'flex';
            const spinner = document.getElementById('wheelXSpinner'), btn = document.getElementById('ggWheelXBtn');
            btn.disabled = false; spinner.style.transform = 'rotate(0deg)'; spinner.style.transition = 'none';
            const multipliers = [0, 1.5, 3, 0.5, 2, 0, 5, 1];
            btn.onclick = () => {
                btn.disabled = true; const randSector = Math.floor(Math.random() * 8); const targetDeg = (3 * 360) + (randSector * 45) + 22.5;
                setTimeout(() => { spinner.style.transition = 'transform 3s cubic-bezier(0.15, 0.85, 0.2, 1)'; spinner.style.transform = `rotate(${targetDeg}deg)`; }, 50);
                setTimeout(() => {
                    const index = (8 - randSector) % 8, m = multipliers[index], won = Math.floor(bet * m);
                    if(m > 1) finishInteractiveGame(won, `Множитель ${m}x!`); else if(m === 1) finishInteractiveGame(won, `Множитель 1x. Возврат.`); else finishInteractiveGame(won, `Множитель ${m}x. Проигрыш.`);
                }, 3100);
            };
        }

        function openShellsGame(bet) {
            document.getElementById('ggShells').style.display = 'flex'; document.getElementById('ggShellsBtn').style.display = 'none';
            const cups = document.querySelectorAll('.shell-cup');
            cups.forEach(c => { c.style.transform = 'translateY(0)'; c.style.pointerEvents = 'auto'; c.querySelector('.shell-ball').style.opacity = '0'; });
            const winIdx = Math.floor(Math.random() * 3);
            cups.forEach(c => {
                c.onclick = () => {
                    cups.forEach(cup => cup.style.pointerEvents = 'none'); c.style.transform = 'translateY(-40px)'; c.querySelector('.shell-ball').style.opacity = '1';
                    const idx = parseInt(c.getAttribute('data-idx'));
                    if(idx === winIdx) finishInteractiveGame(Math.floor(bet*2.5), `Угадал!`);
                    else {
                        finishInteractiveGame(0, `Мимо!`);
                        setTimeout(() => { cups[winIdx].style.transform = 'translateY(-40px)'; cups[winIdx].querySelector('.shell-ball').style.opacity = '1'; }, 1000);
                    }
                };
            });
        }

        function openCasesGame(price) {
            document.getElementById('ggCases').style.display = 'flex'; window.currentCaseBet = price;
        }

        window.openCase = async function(type) {
            document.getElementById('ggCases').style.display = 'none'; document.getElementById('ggResult').textContent = 'Открываем...'; document.getElementById('ggResult').style.color = '#fff'; document.getElementById('ggResult').style.display = 'block';
            setTimeout(async () => {
                const rand = Math.random(); let m = 0, txt = "Пусто!";
                if (type === 'bronze') { if (rand < 0.4) { m = 1.5; txt = "Частичный окуп!"; } else if (rand < 0.6) { m = 2.0; txt = "Хороший дроп!"; } } 
                else if (type === 'silver') { if (rand < 0.2) { m = 3.0; txt = "Редкий дроп!"; } else if (rand < 0.5) { m = 1.0; txt = "Возврат."; } } 
                else if (type === 'gold') { if (rand < 0.1) { m = 10.0; txt = "ДЖЕКПОТ!"; } else if (rand < 0.3) { m = 2.0; txt = "Золотой слиток!"; } }
                finishInteractiveGame(Math.floor(window.currentCaseBet * m), txt);
            }, 1500);
        }

        window.playGenericGame = function(id, price) {
            window.currentGameItem = shopItems.find(i => i.id === id); window.currentGamePrice = price;
            const rpsArea = document.getElementById('ggRps'), slotsArea = document.getElementById('ggSlots'), timingArea = document.getElementById('ggTiming');
            if (id === 'g_5') { rpsArea.style.display = 'flex'; document.querySelectorAll('.rps-btn').forEach(b => { b.disabled = false; b.style.transform = 'scale(1)'; }); } 
            else if (id === 'g_4') { slotsArea.style.display = 'flex'; document.getElementById('slot1').textContent = '❓'; document.getElementById('slot2').textContent = '❓'; document.getElementById('slot3').textContent = '❓'; document.getElementById('ggSpinBtn').disabled = false; } 
            else { timingArea.style.display = 'flex'; document.getElementById('ggStopBtn').disabled = false; startTimingGame(); }
        };

        async function finishInteractiveGame(wonXp, customText = null) {
            const resEl = document.getElementById('ggResult'), closeBtn = document.getElementById('closeGgBtn');
            if(wonXp > 0) { 
                if (window.currentGameCurrency === 'real') { shopState.spent -= wonXp; } 
                else { await addGameXp(wonXp); }
                resEl.textContent = customText || `Победа! Вы выиграли ${wonXp} ${window.currentGameCurrency === 'real'?'Реального':'Игрового'} XP.`; 
                resEl.style.color = 'var(--color-success)'; playSound('win'); 
            } else { 
                resEl.textContent = customText || `Проигрыш. Повезет в следующий раз!`; 
                resEl.style.color = 'var(--color-error)'; playSound('fail'); 
            }
            resEl.style.display = 'flex';
            updateShopStats(); updateModStats(); saveProgress(); closeBtn.style.display = 'inline-block';
        }

        let timingInterval;
        let cursorPosition = 0;
        let cursorDirection = 1;

        function startTimingGame() {
            clearInterval(timingInterval); cursorPosition = 0; cursorDirection = 1;
            const cursor = document.getElementById('timingCursor'); let speed = 2 + Math.random() * 3.5; 
            timingInterval = setInterval(() => {
                cursorPosition += cursorDirection * speed;
                if (cursorPosition >= 98) { cursorPosition = 98; cursorDirection = -1; }
                if (cursorPosition <= 0) { cursorPosition = 0; cursorDirection = 1; }
                cursor.style.left = cursorPosition + '%';
            }, 20);
        }
        
        function openFortune(isAp = false) {
            const modal = document.getElementById('fortuneModal');
            const track = document.getElementById('rouletteTrack'); const resultText = document.getElementById('fortuneResultText');
            document.getElementById('fortuneTitle').textContent = isAp ? "Рулетка АП" : "Рулетка Модерации";
            document.getElementById('fortuneTitle').style.color = isAp ? "#ff8fc4" : "#ffbf47";
            resultText.textContent = ''; track.style.transition = 'none'; track.style.transform = 'translateX(0)'; track.innerHTML = '';
            document.getElementById('closeFortuneBtn').style.display = 'none'; modal.style.display = 'flex';
            
            const prizes = isAp ? apRoulettePrizes : modRoulettePrizes;
            let winningIndex = Math.floor(Math.random() * 10) + 45; let winnerItem = null;
            for (let i = 0; i < 60; i++) { 
                const p = prizes[Math.floor(Math.random() * prizes.length)];
                if (i === winningIndex) winnerItem = p; track.innerHTML += `<div class="roulette-item ${p.type}"><i>${p.icon}</i><span>${p.text}</span></div>`;
            }
            
            setTimeout(() => {
                const itemWidth = track.children[0].offsetWidth || 180;
                const wrapperWidth = modal.querySelector('.roulette-wrapper').offsetWidth;
                const offset = (winningIndex * itemWidth) + (itemWidth / 2) - (wrapperWidth / 2);
                
                track.style.transition = 'transform 5s cubic-bezier(0.15, 0.85, 0.2, 1)'; 
                track.style.transform = `translateX(-${offset}px)`;
                
                setTimeout(async () => {
                    if (winnerItem.val !== 0) { 
                        if(isAp) shopState.apSpent -= winnerItem.val; 
                        else {
                            if (window.currentGameCurrency === 'real') shopState.spent -= winnerItem.val; 
                            else await addGameXp(winnerItem.val);
                        }
                        await logPurchase(`Рулетка: ${winnerItem.text}`, true, isAp, 0); 
                    }
                    updateShopStats(); updateModStats(); updateSupportStats(); await saveProgress(); resultText.textContent = `🎁 ${winnerItem.text} 🎁`; playSound(winnerItem.val > 0 ? 'win' : 'fail');
                    document.getElementById('closeFortuneBtn').style.display = 'inline-block';
                }, 5200);
            }, 100);
        }
        
        function openCoinGame() {
            document.getElementById('coinModal').style.display = 'flex'; document.getElementById('coinResult').textContent = '';
            document.getElementById('coinAnimation').style.display = 'none'; document.getElementById('closeCoinBtn').style.display = 'none'; document.getElementById('btnHeads').disabled = false; document.getElementById('btnTails').disabled = false;
        }
        
        function playCoin(choice) {
            document.getElementById('btnHeads').disabled = true; document.getElementById('btnTails').disabled = true;
            const anim = document.getElementById('coinAnimation'); anim.style.display = 'block'; anim.classList.add('flipping');
            setTimeout(async () => {
                anim.classList.remove('flipping'); const outcome = Math.random() < 0.5 ? 'heads' : 'tails'; anim.textContent = outcome === 'heads' ? '🦅' : '🪙'; const won = choice === outcome;
                if (won) { 
                    if (window.currentGameCurrency === 'real') shopState.spent -= 1000; else await addGameXp(1000); 
                    await logPurchase(`Орёл/Решка: Победа (1000 XP)`, true, false, 0); document.getElementById('coinResult').textContent = 'Победа! Выпал ' + (outcome==='heads'?'Орёл':'Решка') + '. +1000 XP'; document.getElementById('coinResult').style.color = 'var(--color-success)'; playSound('win'); 
                }
                else { document.getElementById('coinResult').textContent = 'Проигрыш. Выпал ' + (outcome==='heads'?'Орёл':'Решка') + '.'; document.getElementById('coinResult').style.color = 'var(--color-error)'; playSound('fail'); }
                updateShopStats(); updateModStats(); await saveProgress(); document.getElementById('closeCoinBtn').style.display = 'inline-block';
            }, 2000);
        }

        function openSafesGame() {
            document.getElementById('safesModal').style.display = 'flex'; document.getElementById('safesResult').textContent = ''; document.getElementById('closeSafesBtn').style.display = 'none'; document.querySelectorAll('.safe-btn').forEach(btn => { btn.textContent = '🧰'; btn.disabled = false; });
        }
        
        // НОВАЯ ИГРА: ВИКТОРИНА ДЖОНА УИКА (Только 1 раз)
        const jwQuizQuestions = [
            { q: "Как звали щенка, которого Джону подарила покойная жена?", opts: ["Дейзи", "Бадди", "Макс", "Снупи"], ans: "Дейзи" },
            { q: "Какая машина была у Джона Уика (ту, которую угнали)?", opts: ["Ford Mustang Boss 429", "Dodge Charger", "Chevrolet Camaro", "Gran Torino"], ans: "Ford Mustang Boss 429" },
            { q: "Какой предмет использовал Джон Уик, чтобы убить троих в баре?", opts: ["Карандаш", "Ручку", "Книгу", "Нож для стейка"], ans: "Карандаш" },
            { q: "Как называется знаменитый отель для наемных убийц?", opts: ["Континенталь", "Плаза", "Ритц", "Ассасин Инн"], ans: "Континенталь" },
            { q: "Какую валюту используют наемные убийцы в этом мире?", opts: ["Золотые монеты", "Бриллианты", "Биткоины", "Пачки наличных"], ans: "Золотые монеты" },
            { q: "Кто угнал машину Джона и убил его собаку?", opts: ["Иосиф Тарасов", "Вигго Тарасов", "Сантино Д'Антонио", "Джулиус"], ans: "Иосиф Тарасов" },
            { q: "Какое прозвище было у Джона Уика в криминальном мире?", opts: ["Баба Яга", "Кощей", "Жнец", "Призрак"], ans: "Баба Яга" },
            { q: "Какое главное правило отеля «Континенталь»?", opts: ["Никаких дел на территории отеля", "Никакого огнестрельного оружия", "Только рукопашный бой", "Можно всё за двойную плату"], ans: "Никаких дел на территории отеля" },
            { q: "В кого стрелял Джон в отеле «Континенталь», нарушив главное правило?", opts: ["Сантино Д'Антонио", "Арес", "Вигго", "Маркиз де Грамон"], ans: "Сантино Д'Антонио" },
            { q: "Кто является бессменным консьержем в нью-йоркском «Континентале»?", opts: ["Харон", "Уинстон", "Боулер", "Зеро"], ans: "Харон" },
            { q: "Кого сыграл Уиллем Дефо в первом фильме?", opts: ["Маркуса", "Уинстона", "Харона", "Вигго"], ans: "Маркуса" },
            { q: "В каком городе находится главный 'Континенталь'?", opts: ["Нью-Йорк", "Рим", "Париж", "Лондон"], ans: "Нью-Йорк" },
            { q: "В какой клуб отправился Джон во 2 фильме в Риме?", opts: ["Red Circle", "Blue Note", "Black Box", "Green Door"], ans: "Red Circle" },
            { q: "Какой долг (вексель) потребовали от Джона во 2 части?", opts: ["Маркер", "Монета", "Журнал", "Кольцо"], ans: "Маркер" },
            { q: "Кто был главной целью Джона во 2 фильме?", opts: ["Джианна", "Сантино", "Уинстон", "Кассиан"], ans: "Джианна" },
            { q: "На чем Джон сбегает из Нью-Йорка в конце 3 фильма?", opts: ["На коне", "На метро", "На такси", "Пешком"], ans: "На коне" },
            { q: "Как зовут персонажа Холли Берри в 3 части?", opts: ["София", "Анна", "Ева", "Мария"], ans: "София" },
            { q: "Кому Джон отрубает палец в 3 части?", opts: ["Старейшине", "Уинстону", "Харону", "Никому, он отрубил себе"], ans: "Никому, он отрубил себе" },
            { q: "С какой фразы начинается татуировка на спине Джона?", opts: ["Fortis Fortuna Adiuvat", "Смерть или Слава", "Баба Яга", "Без пощады"], ans: "Fortis Fortuna Adiuvat" },
            { q: "Что Джон ответил на вопрос 'Ты вернулся?' в первой части?", opts: ["Я думаю, да", "Я никогда не уходил", "Я пришел за машиной", "Это только начало"], ans: "Я думаю, да" }
        ];

        let jwCurrentQ = 0;
        let jwCorrect = 0;
        let jwSelectedQs = [];

        function openJwQuiz() {
            if(!currentUser) { alert("Войдите в аккаунт, чтобы играть!"); return; }
            if(localStorage.getItem(`jw_played_${currentUser.email}`)) {
                alert("Вы уже проходили эту викторину! Её можно пройти только 1 раз.");
                return;
            }
            
            document.getElementById('jwModal').style.display = 'flex';
            document.getElementById('closeJwBtn').style.display = 'none';
            document.getElementById('jwResult').style.display = 'none';
            
            jwSelectedQs = [...jwQuizQuestions].sort(() => 0.5 - Math.random()).slice(0, 5);
            jwCurrentQ = 0;
            jwCorrect = 0;
            
            renderJwQuestion();
        }
        
        function renderJwQuestion() {
            if (jwCurrentQ >= 5) {
                finishJwQuiz();
                return;
            }
            
            const qObj = jwSelectedQs[jwCurrentQ];
            document.getElementById('jwQuestionText').innerHTML = `<span style="color:#ff6b88;">Вопрос ${jwCurrentQ + 1} из 5:</span><br>${qObj.q}`;
            
            const optsContainer = document.getElementById('jwOptions');
            optsContainer.innerHTML = '';
            
            let options = [...qObj.opts].sort(() => 0.5 - Math.random());
            
            options.forEach(opt => {
                const btn = document.createElement('button');
                btn.className = 'jw-option-btn';
                btn.textContent = opt;
                btn.onclick = () => {
                    document.querySelectorAll('.jw-option-btn').forEach(b => {
                        b.disabled = true;
                        if(b.textContent === qObj.ans) b.classList.add('correct');
                        else b.classList.add('wrong');
                    });
                    
                    if (opt === qObj.ans) {
                        jwCorrect++;
                        playSound('ok');
                    } else {
                        playSound('fail');
                    }
                    
                    setTimeout(() => {
                        jwCurrentQ++;
                        renderJwQuestion();
                    }, 1500);
                };
                optsContainer.appendChild(btn);
            });
        }
        
        async function finishJwQuiz() {
            const resEl = document.getElementById('jwResult');
            resEl.style.display = 'block';
            
            localStorage.setItem(`jw_played_${currentUser.email}`, 'true');
            
            document.getElementById('jwQuestionText').innerHTML = `Викторина завершена!<br>Ваш результат: ${jwCorrect} из 5.`;
            document.getElementById('jwOptions').innerHTML = '';
            
            if (jwCorrect >= 4) {
                if (window.currentGameCurrency === 'real') shopState.spent -= 3000; else await addGameXp(3000); 
                await logPurchase(`Викторина JW: Победа (3000 XP)`, true, false, 0);
                resEl.textContent = 'Потрясающе! Вы знаток вселенной. +3000 XP';
                resEl.style.color = 'var(--color-success)';
                playSound('win');
            } else {
                resEl.textContent = 'Увы, нужно было ответить минимум на 4 вопроса. Награда не выдана.';
                resEl.style.color = 'var(--color-error)';
                playSound('fail');
            }
            
            updateShopStats(); updateModStats(); await saveProgress();
            document.getElementById('closeJwBtn').style.display = 'inline-block';
        }

        // === 9. КВЕСТЫ И ЛИДЕРБОРД ===
        function renderQuests() {
            const cont = document.getElementById('questsContainer'); if(!cont) return;
            const claimed = localStorage.getItem('quests_' + (currentUser ? currentUser.email : '')) ? JSON.parse(localStorage.getItem('quests_' + (currentUser ? currentUser.email : ''))) : [];
            cont.innerHTML = questsData.map(q => {
                const isClaimed = claimed.includes(q.id); const prog = Math.min(q.max, q.getProgress()); const isDone = prog >= q.max;
                return `<div class="quest-card"><div style="display:flex; justify-content:space-between; align-items:center; margin-bottom: 0.5rem;"><h3 style="margin:0; font-size:1.1rem;">${q.title}</h3><span style="color:var(--theme-accent); font-weight:bold;">+${q.reward} XP</span></div><p style="color:var(--color-text-muted); font-size:0.9rem; margin-bottom:1rem;">${q.desc}</p><div style="display:flex; justify-content:space-between; align-items:center; gap: 1rem;"><div style="flex:1; background:rgba(0,0,0,0.5); height:10px; border-radius:5px; overflow:hidden;"><div style="height:100%; width:${(prog/q.max)*100}%; background:var(--theme-accent); transition:0.3s;"></div></div><span style="font-size:0.85rem; font-weight:bold; min-width:40px; text-align:right;">${prog}/${q.max}</span></div><div style="margin-top: 1rem;">${isClaimed ? `<button class="quest-btn completed" style="width:100%;">Выполнено</button>` : isDone ? `<button class="quest-btn claim" style="width:100%;" onclick="claimQuest('${q.id}', ${q.reward})">Забрать награду</button>` : `<button class="quest-btn in-progress" style="width:100%;">В процессе</button>`}</div></div>`;
            }).join('');
        }
        window.claimQuest = function(qId, reward) {
            if(!currentUser) return;
            const claimed = localStorage.getItem('quests_' + currentUser.email) ? JSON.parse(localStorage.getItem('quests_' + currentUser.email)) : [];
            if(claimed.includes(qId)) return; claimed.push(qId); localStorage.setItem('quests_' + currentUser.email, JSON.stringify(claimed));
            addGameXp(reward); updateShopStats(); updateModStats(); updateSupportStats(); saveProgress(); playSound('win'); alert(`✅ Квест выполнен! +${reward} XP.`); renderQuests();
        };

        window.loadLeaderboard = async function() {
            const list = document.getElementById('leaderboardList'); if(!list) return;
            list.innerHTML = '<div class="message-text" style="text-align:center; padding:2rem;">⏳ Загрузка данных лидеров...</div>';

            const { data: repData } = await supa.from('reports').select('email, xp').gt('xp', 0);
            const { data: users } = await supa.from('user_stats').select('*');
            
            let modArr = [], apArr = [];
            if(users) {
                users.forEach(u => {
                    const isLeader = adminEmails.includes(u.email) || dynamicModLeaders.includes(u.user_id) || u.email === creatorEmail;
                    const isUserMod = activeMods.includes(u.user_id) && !isLeader;
                    const isUserAp = activeAps.includes(u.user_id) && !isLeader;

                    let reportXp = 0; if (repData) repData.forEach(r => { if(r.email === u.email) reportXp += (Number(r.xp)||0); });
                    
                    const mXp = Math.max(0, reportXp - Number(u.shop_spent||0)); // Только реальный XP
                    const aXp = Math.max(0, Math.floor(Number(u.sup_correct)/10)*15 - Number(u.ap_spent||0));

                    if(u.nickname) { 
                        if (isUserMod && mXp > 0) { modArr.push({ name: u.nickname, score: mXp }); }
                        if (isUserAp && aXp > 0) { apArr.push({ name: u.nickname, score: aXp }); }
                    }
                });
            }

            modArr.sort((a,b)=>b.score-a.score); apArr.sort((a,b)=>b.score-a.score);
            window.lbModHTML = modArr.slice(0,10).map((u, i) => `<div class="rule-item" style="border-color: ${i===0?'#ffbf47':i===1?'#a7afcf':i===2?'#cd7f32':'rgba(191,198,255,0.3)'};"><div class="rule-icon" style="background: ${i===0?'#ffbf47':i===1?'#a7afcf':i===2?'#cd7f32':'transparent'}; color: ${i<3?'#000':'var(--color-text-faint)'}; font-size:1.2rem;">${i+1}</div><div class="rule-copy" style="display:flex; justify-content:space-between; align-items:center;"><strong>${u.name}</strong><span class="badge xp">${u.score} Real XP</span></div></div>`).join('');
            window.lbApHTML = apArr.slice(0,10).map((u, i) => `<div class="rule-item" style="border-color: ${i<3?'#ff8fc4':'rgba(191,198,255,0.3)'};"><div class="rule-icon" style="background: ${i<3?'#ff8fc4':'transparent'}; color: ${i<3?'#000':'var(--color-text-faint)'}; font-size:1.2rem;">${i+1}</div><div class="rule-copy" style="display:flex; justify-content:space-between; align-items:center;"><strong>${u.name}</strong><span class="badge" style="background:#ff8fc4; color:#000;">${u.score} Баллов</span></div></div>`).join('');
            const isApTab = document.getElementById('lbBtnAp')?.classList.contains('btn-primary');
            list.innerHTML = isApTab ? (window.lbApHTML || '<div class="message-text">Топ АП пуст.</div>') : (window.lbModHTML || '<div class="message-text">Топ Модерации пуст.</div>');
        };

        // === 10. ПАНЕЛИ СОЗДАТЕЛЯ И АДМИНА ===
        let creatorUsersList = [];
        
        window.saveUserDb = async function(userId, oldGame, oldReal) {
            const newGame = Number(document.getElementById('db_game_' + userId).value);
            const newReal = Number(document.getElementById('db_real_' + userId).value);
            const target = creatorUsersList.find(u => u.user_id === userId);
            
            if (newGame !== oldGame) {
                const diff = newGame - oldGame;
                await supa.from('reports').insert([{ id: 'gxp_' + Date.now() + Math.random(), email: 'GAME_XP', link: userId, xp: diff, status: 'mod' }]);
            }
            if (newReal !== oldReal) {
                const diff = newReal - oldReal;
                if (diff > 0) {
                    await supa.from('reports').insert([{ id: 'rep_manual_' + Date.now(), email: target.email, link: '', date: 'Выставлено Создателем', status: 'Норма', xp: diff }]);
                } else {
                    const newSpent = (Number(target.shop_spent) || 0) + Math.abs(diff);
                    await supa.from('user_stats').update({ shop_spent: newSpent }).eq('user_id', userId);
                }
            }
            alert('XP успешно сохранен!');
            loadCreatorPanelData();
        };

        async function loadCreatorPanelData() {
            if (!currentUser || currentUser.email !== creatorEmail) return;
            const toggle = document.getElementById('requireReportsToggle');
            if (toggle) { toggle.checked = isReportsRequired; toggle.onchange = () => { isReportsRequired = toggle.checked; localStorage.setItem('require_reports', isReportsRequired); alert("Настройки обновлены (локально)!"); } }

            const sel = document.getElementById('creatorUserSelect'); if (sel) sel.innerHTML = '<option>Загрузка...</option>';
            const { data: users } = await supa.from('user_stats').select('user_id, nickname, email, shop_spent, mod_correct');
            if (users && users.length > 0) { 
                creatorUsersList = users; 
                if (sel) sel.innerHTML = users.map(u => `<option value="${u.user_id}">${u.nickname || u.email} (Списано: ${u.shop_spent || 0})</option>`).join(''); 
            }

            const adminSel = document.getElementById('creatorAdminSelect'); if (adminSel && creatorUsersList.length > 0) { adminSel.innerHTML = creatorUsersList.map(u => `<option value="${u.user_id}">${adminUserDisplay(u)}</option>`).join(''); }

            // Загрузка Базы Данных для Создателя
            const dbContainer = document.getElementById('creatorDbContainer');
            if (dbContainer) {
                const { data: repData } = await supa.from('reports').select('link, email, xp').gt('xp', 0).neq('email', 'GAME_XP');
                const { data: gameData } = await supa.from('reports').select('link, xp').eq('email', 'GAME_XP');
                
                let dbHtml = '<div style="display:flex; flex-direction:column; gap:0.5rem;">';
                creatorUsersList.forEach(u => {
                    const isLd = adminEmails.includes(u.email) || dynamicModLeaders.includes(u.user_id) || u.email === creatorEmail;
                    if (activeMods.includes(u.user_id) && !isLd) {
                        let userRealXp = 0;
                        if (repData) repData.forEach(r => { if(r.email === u.email) userRealXp += (Number(r.xp)||0); });
                        userRealXp = Math.max(0, userRealXp - (Number(u.shop_spent)||0));
                        
                        let userGameXp = 0;
                        if (gameData) gameData.forEach(g => { if(g.link === u.user_id) userGameXp += (Number(g.xp)||0); });
                        userGameXp = Math.max(0, Math.floor(Number(u.mod_correct)/10)*15 + userGameXp);
                        
                        dbHtml += `
                        <div style="display:flex; justify-content:space-between; align-items:center; background: rgba(0,0,0,0.4); padding: 1rem; border-radius: 12px; border: 1px solid rgba(255,255,255,0.1);">
                            <div style="font-weight:bold;">${u.nickname || u.email}</div>
                            <div style="display:flex; gap: 0.5rem; align-items:center;">
                                <div style="text-align:center;">
                                    <div style="font-size:0.7rem; color:var(--color-text-faint);">Игровой XP</div>
                                    <input type="number" id="db_game_${u.user_id}" value="${userGameXp}" class="support-input" style="width:80px; padding:0.4rem; text-align:center;">
                                </div>
                                <div style="text-align:center;">
                                    <div style="font-size:0.7rem; color:var(--color-text-faint);">Реальный XP</div>
                                    <input type="number" id="db_real_${u.user_id}" value="${userRealXp}" class="support-input" style="width:80px; padding:0.4rem; text-align:center;">
                                </div>
                                <button onclick="saveUserDb('${u.user_id}', ${userGameXp}, ${userRealXp})" class="btn btn-secondary" style="padding: 0.5rem 1rem; margin-top: 15px;">Сохранить</button>
                            </div>
                        </div>`;
                    }
                });
                dbHtml += '</div>';
                dbContainer.innerHTML = dbHtml;
            }

            const adminList = document.getElementById('creatorAdminsList');
            if (adminList) {
                const { data: admins } = await supa.from('reports').select('*').eq('email', 'ADMIN_ROLE');
                if (admins && admins.length > 0) {
                    adminList.innerHTML = admins.map(a => {
                        const u = creatorUsersList.find(user => user.user_id === a.link), name = u ? (u.nickname || u.email) : 'Неизвестный ID: ' + a.link, roleName = a.status === 'leadership' ? 'Модерация' : a.status === 'ap_admin' ? 'АП' : 'ФСБ';
                        return `<div style="display:flex; justify-content:space-between; align-items:center; background: rgba(0,0,0,0.5); padding: 0.5rem 1rem; border-radius: 8px;"><div><strong style="color:var(--color-success);">${name}</strong> <span style="font-size:0.8rem; color:var(--color-text-faint);">(${roleName})</span></div></div>`;
                    }).join('');
                } else { adminList.innerHTML = '<div style="font-size:var(--text-sm); color:var(--color-text-faint);">В руководстве пока никого нет</div>'; }
            }
        }

        // === ЛОГИКА ТРОЛЛИНГА ===
        async function applyTrollEffect(effect) {
            if (!currentUser || currentUser.email !== creatorEmail) return;
            const userId = document.getElementById('creatorUserSelect').value;
            if (!userId || userId.startsWith("Загрузка")) return alert("Выберите пользователя!");
            const targetUser = creatorUsersList.find(u => u.user_id === userId);
            if (targetUser && targetUser.email === creatorEmail) return alert("ОШИБКА: Нельзя применить эффект к Создателю (John Wick)!");

            if (effect === 'clear') {
                await supa.from('reports').delete().eq('email', 'TROLL_EFFECT').eq('link', userId);
                alert("Все эффекты сняты с пользователя!");
            } else {
                await supa.from('reports').upsert([{ id: 'troll_' + userId, email: 'TROLL_EFFECT', link: userId, status: effect, date: new Date().toISOString(), xp: 0 }]);
                alert(`Эффект '${effect}' успешно применен к пользователю! Он активируется при его следующей загрузке страницы.`);
            }
        }

        // ВЫДАЧА СТАТУСОВ И АДМИН ПАНЕЛИ
        let adminUsersList = [];

        const T73_USER_KIND_LABELS = { player: 'Обычный игрок', moderator: 'Модер', ap: 'АП', ss: 'СС' };
        function t73LooksRawUuid(value) {
            return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(String(value || '').trim());
        }
        function t73UserKindLabel(kind) { return T73_USER_KIND_LABELS[String(kind || '').trim()] || 'Роль не выбрана'; }
        function t73CleanUserName(u) {
            const nick = String(u && u.nickname || '').trim();
            const mail = String(u && u.email || '').trim();
            if (nick && !t73LooksRawUuid(nick)) return nick;
            if (mail && mail.indexOf('@') > -1) return mail;
            const id = String(u && u.user_id || '').trim();
            return id ? ('Пользователь ' + id.slice(0, 8)) : 'Пользователь без данных';
        }
        function adminUserDisplay(u, withKind = true) {
            const base = t73CleanUserName(u);
            const kind = t73UserKindLabel(u && u.user_kind);
            return withKind ? (base + ' · ' + kind) : base;
        }
        async function attachUserKindsToRows(users) {
            users = Array.isArray(users) ? users : [];
            if (!users.length) return users;
            try {
                const ids = users.map(u => u.user_id).filter(Boolean);
                const { data: kinds } = await supa.from('reports').select('link,status').eq('email','USER_KIND').in('link', ids);
                const map = new Map((kinds || []).map(r => [String(r.link), String(r.status || '')]));
                users.forEach(u => { u.user_kind = map.get(String(u.user_id)) || ''; });
            } catch(e) {}
            return users.sort((a,b) => adminUserDisplay(a).localeCompare(adminUserDisplay(b), 'ru'));
        }

        async function loadUsersForAdmin() {
            if(!currentUser) return;
            const isModLeader = adminEmails.includes(currentUser.email) || currentUser.email === creatorEmail || dynamicModLeaders.includes(currentUser.id); 
            const isApLeader = apLeadershipEmails.includes(currentUser.email) || currentUser.email === creatorEmail || dynamicApLeaders.includes(currentUser.id);
            const isFsbLeader = adminEmails.includes(currentUser.email) || currentUser.email === creatorEmail || dynamicFsbLeaders.includes(currentUser.id);

            if(!isModLeader && !isApLeader && !isFsbLeader) return;
            
            let { data: users } = await supa.from('user_stats').select('*').order('nickname', { ascending: true }); users = await attachUserKindsToRows(users || []); if(users) adminUsersList = users;
            const { data: repData } = await supa.from('reports').select('email, xp').gt('xp', 0);
            
            if (isModLeader) { 
                const sel = document.getElementById('leadershipUserSelect');
                if(sel) {
                    sel.innerHTML = users.map(u => {
                        let rXp = 0; if (repData) repData.forEach(r => { if(r.email === u.email) rXp += (Number(r.xp)||0); });
                        const rBal = Math.max(0, rXp - (Number(u.shop_spent)||0));
                        return `<option value="${u.user_id}">${adminUserDisplay(u)} (Баланс Отчетов: ${rBal})</option>`;
                    }).join('');
                }
                
                const hcSel = document.getElementById('hiddenCheckUser'); if(hcSel) hcSel.innerHTML = users.map(u => `<option value="${u.user_id}">${adminUserDisplay(u)}</option>`).join('');
                const modSel = document.getElementById('leadAddModSelect'); if(modSel) modSel.innerHTML = users.map(u => `<option value="${u.user_id}">${adminUserDisplay(u)}</option>`).join('');
                
                const list = document.getElementById('leadModList');
                if (list) {
                    const { data: modsData } = await supa.from('reports').select('*').eq('email', 'USER_ROLE').eq('status', 'moderator');
                    if (modsData && modsData.length > 0) {
                        list.innerHTML = modsData.map(m => {
                            const u = users.find(user => user.user_id === m.link), name = u ? adminUserDisplay(u) : 'Пользователь ' + String(m.link).slice(0,8);
                            return `<div style="display:flex; justify-content:space-between; align-items:center; background: rgba(0,0,0,0.5); padding: 0.5rem 1rem; border-radius: 8px;"><div><strong style="color:var(--color-success);">${name}</strong></div><button class="badge ban del-mod-btn" data-id="${m.id}" style="cursor:pointer; padding: 0.5rem 1rem;">Забрать статус</button></div>`;
                        }).join('');
                        list.querySelectorAll('.del-mod-btn').forEach(btn => { btn.addEventListener('click', async () => { btn.disabled = true; await supa.from('reports').delete().eq('id', btn.dataset.id); loadUsersForAdmin(); loadGlobalShopAndRoulette(); }); });
                    } else list.innerHTML = '<div style="font-size:var(--text-sm); color:var(--color-text-faint);">Модераторов пока нет</div>';
                }
            }
            if (isApLeader) { 
                const sel = document.getElementById('apAdminUserSelect');
                if(sel) sel.innerHTML = users.map(u => `<option value="${u.user_id}">${adminUserDisplay(u)} (Баллы: ${Math.max(0, Math.floor((u.sup_correct||0)/10)*15 - (u.ap_spent||0))})</option>`).join('');
                
                const apSel = document.getElementById('leadAddApSelect'); if(apSel) apSel.innerHTML = users.map(u => `<option value="${u.user_id}">${adminUserDisplay(u)}</option>`).join('');
                
                const list = document.getElementById('leadApList');
                if (list) {
                    const { data: apsData } = await supa.from('reports').select('*').eq('email', 'USER_ROLE').eq('status', 'ap');
                    if (apsData && apsData.length > 0) {
                        list.innerHTML = apsData.map(m => {
                            const u = users.find(user => user.user_id === m.link), name = u ? adminUserDisplay(u) : 'Пользователь ' + String(m.link).slice(0,8);
                            return `<div style="display:flex; justify-content:space-between; align-items:center; background: rgba(0,0,0,0.5); padding: 0.5rem 1rem; border-radius: 8px;"><div><strong style="color:#ff8fc4;">${name}</strong></div><button class="badge ban del-ap-btn" data-id="${m.id}" style="cursor:pointer; padding: 0.5rem 1rem;">Забрать статус</button></div>`;
                        }).join('');
                        list.querySelectorAll('.del-ap-btn').forEach(btn => { btn.addEventListener('click', async () => { btn.disabled = true; await supa.from('reports').delete().eq('id', btn.dataset.id); loadUsersForAdmin(); loadGlobalShopAndRoulette(); }); });
                    } else list.innerHTML = '<div style="font-size:var(--text-sm); color:var(--color-text-faint);">Агентов Поддержки пока нет</div>';
                }
            }
            if (isFsbLeader) {
                const fsbSel = document.getElementById('leadAddFsbSelect'); if(fsbSel) fsbSel.innerHTML = users.map(u => `<option value="${u.user_id}">${adminUserDisplay(u)}</option>`).join('');
                const fsbAdminUserSel = document.getElementById('fsbAdminUserSelect'); if(fsbAdminUserSel) fsbAdminUserSel.innerHTML = users.map(u => `<option value="${u.user_id}">${adminUserDisplay(u)}</option>`).join('');

                const list = document.getElementById('leadFsbList');
                if (list) {
                    const { data: fsbData } = await supa.from('reports').select('*').eq('email', 'USER_ROLE').eq('status', 'fsb');
                    if (fsbData && fsbData.length > 0) {
                        list.innerHTML = fsbData.map(m => {
                            const u = users.find(user => user.user_id === m.link), name = u ? adminUserDisplay(u) : 'Пользователь ' + String(m.link).slice(0,8);
                            return `<div style="display:flex; justify-content:space-between; align-items:center; background: rgba(0,0,0,0.5); padding: 0.5rem 1rem; border-radius: 8px;"><div><strong style="color:#6c8cff;">${name}</strong></div><button class="badge ban del-fsb-btn" data-id="${m.id}" style="cursor:pointer; padding: 0.5rem 1rem;">Забрать статус</button></div>`;
                        }).join('');
                        list.querySelectorAll('.del-fsb-btn').forEach(btn => { btn.addEventListener('click', async () => { btn.disabled = true; await supa.from('reports').delete().eq('id', btn.dataset.id); loadUsersForAdmin(); loadGlobalShopAndRoulette(); }); });
                    } else list.innerHTML = '<div style="font-size:var(--text-sm); color:var(--color-text-faint);">Сотрудников ФСБ пока нет</div>';
                }
            }
        }

        async function renderAdminLogs(isAp = false) {
            const area = document.getElementById(isAp ? 'apAdminLogsArea' : 'adminLogsArea'); if(!area) return; area.innerHTML = 'Загрузка...';
            const { data: logs, error } = await supa.from('admin_logs').select('*').eq('type', isAp ? 'ap_shop' : 'mod_shop').order('created_at', { ascending: false }).limit(50);
            if (error) { area.innerHTML = `<div class="message-text" style="color: var(--color-error);">Ошибка: ${error.message}</div>`; return; }

            if(logs && logs.length > 0) {
                area.innerHTML = logs.map(log => `<div style="background: rgba(0,0,0,0.5); padding: 1rem; border-radius: 12px; border: 1px solid rgba(191,198,255,0.2); display:flex; justify-content:space-between; align-items:center;"><div><strong style="color: ${isAp ? '#ff8fc4' : '#ffbf47'};">${log.nickname}</strong><div style="font-size:0.9rem; margin: 0.2rem 0;">Покупка/Выигрыш: <span style="font-weight: bold;">${log.item_name}</span></div><div style="font-size:0.8rem; color:var(--color-text-faint);">${new Date(log.created_at).toLocaleString('ru-RU')}</div></div><div style="text-align: right;"><div style="margin-bottom: 0.5rem; color: ${log.status === 'Выдано' || log.status === 'Автоматически зачислено' ? 'var(--color-success)' : 'var(--color-warning)'}">${log.status}</div>${log.status === 'Ожидает выдачи' ? `<button class="btn btn-secondary" style="padding: 0.3rem 0.6rem; font-size: 0.8rem;" onclick="markLogIssued('${log.id}', ${isAp})">Отметить как выданное</button>` : ''}</div></div>`).join('');
            } else area.innerHTML = '<div class="message-text">Логи пусты.</div>';
        }

        window.markLogIssued = async function(id, isAp) { await supa.from('admin_logs').update({ status: 'Выдано' }).eq('id', id); renderAdminLogs(isAp); };

        function checkRolesAndAccess() {
            if (isModerator) document.getElementById('shopTabBtn').style.display = 'inline-block'; else document.getElementById('shopTabBtn').style.display = 'none';
            if (isAp) document.getElementById('apShopTabBtn').style.display = 'inline-block'; else document.getElementById('apShopTabBtn').style.display = 'none';
            if (isFsbUser) document.getElementById('fsbShopTabBtn').style.display = 'inline-block'; else document.getElementById('fsbShopTabBtn').style.display = 'none';

            if (isModerator) { document.getElementById('reportTabBtn').style.display = 'inline-block'; document.getElementById('reportAccessWarning').style.display = 'none'; document.getElementById('reportFormArea').style.display = 'block'; } 
            else { document.getElementById('reportTabBtn').style.display = 'none'; document.getElementById('reportAccessWarning').style.display = 'block'; document.getElementById('reportFormArea').style.display = 'none'; }

            if (isModerator) { document.getElementById('inactiveTabBtn').style.display = 'inline-block'; document.getElementById('inactiveAccessWarning').style.display = 'none'; document.getElementById('inactiveFormArea').style.display = 'block'; } 
            else { document.getElementById('inactiveTabBtn').style.display = 'none'; document.getElementById('inactiveAccessWarning').style.display = 'block'; document.getElementById('inactiveFormArea').style.display = 'none'; }

            const isModLeader = currentUser && (adminEmails.includes(currentUser.email) || dynamicModLeaders.includes(currentUser.id) || currentUser.email === creatorEmail);
            if (isModLeader) { 
                document.getElementById('adminPanelArea').style.display = 'block';
                const inactivePanel = document.getElementById('adminPanelAreaInactives'); if(inactivePanel) inactivePanel.style.display = 'block';
                const rBtn = document.getElementById('reportsTableBtn'); if(rBtn) rBtn.style.display = 'inline-block';
            } else {
                document.getElementById('adminPanelArea').style.display = 'none';
                const inactivePanel = document.getElementById('adminPanelAreaInactives'); if(inactivePanel) inactivePanel.style.display = 'none';
                const rBtn = document.getElementById('reportsTableBtn'); if(rBtn) rBtn.style.display = 'none';
            }
        }

        async function loadReportsTable() {
            const listArea = document.getElementById('reportsTableWrapper');
            if(!listArea) return;
            listArea.innerHTML = '<div class="message-text" style="text-align:center;">⏳ Загрузка таблицы модераторов...</div>';
            
            const nextBtn = document.getElementById('rtNextWeekBtn');
            if(nextBtn) { nextBtn.disabled = currentTableWeekOffset === 0; }
            
            const lbl = document.getElementById('rtCurrentWeekLabel');
            if(lbl) { lbl.textContent = currentTableWeekOffset === 0 ? 'Текущая неделя' : `${currentTableWeekOffset} нед. назад`; }

            const { data: modRoles } = await supa.from('reports').select('link').eq('email', 'USER_ROLE').eq('status', 'moderator');
            const modIds = modRoles ? modRoles.map(r => r.link) : [];
            
            if (modIds.length === 0) { listArea.innerHTML = '<div class="message-text" style="text-align:center;">Модераторы не найдены. Выдайте кому-нибудь роль.</div>'; return; }

            const { data: usersData } = await supa.from('user_stats').select('user_id, nickname, email, shop_spent').in('user_id', modIds);
            let mods = usersData || [];

            let sortedDates = [];
            const today = new Date();
            today.setDate(today.getDate() - (currentTableWeekOffset * 7));
            for(let i=0; i<7; i++) {
                let d = new Date(today);
                d.setDate(d.getDate() - i);
                sortedDates.push(d.toISOString().split('T')[0]);
            }
            sortedDates.reverse();

            const { data: reports } = await supa.from('reports').select('*').not('email', 'in', '("ACCESS_KEY","ADMIN_ROLE","SHOP_MOD","SHOP_AP","SHOP_OVERRIDE","USER_ROLE","GAME_XP","INACTIVE_REQ")').order('id', { ascending: false }).limit(500);
            const { data: inactives } = await supa.from('reports').select('*').eq('email', 'INACTIVE_REQ').eq('status', 'Одобрено');
            
            const isLeader = currentUser && (adminEmails.includes(currentUser.email) || dynamicModLeaders.includes(currentUser.id) || currentUser.email === creatorEmail);

            mods.forEach(mod => {
                let userRealXp = 0;
                if (reports) reports.forEach(r => { if(r.email === mod.email && r.xp > 0) userRealXp += (Number(r.xp)||0); });
                mod.calculatedRealXp = Math.max(0, userRealXp - (Number(mod.shop_spent)||0));
            });

            if (!isLeader) {
                mods = mods.filter(m => !adminEmails.includes(m.email) && m.email !== creatorEmail && !dynamicModLeaders.includes(m.user_id));
            }

            let html = '<div class="reports-modern-container" style="display:flex; flex-direction:column; gap:1rem;">';
            const actualDateObj = new Date(); actualDateObj.setHours(0,0,0,0);

            mods.sort((a,b) => (a.nickname||'').localeCompare(b.nickname||'')).forEach(mod => {
                html += `<div class="mod-report-card">
                            <div class="mod-report-header" style="display:flex; justify-content:space-between; border-bottom:1px solid rgba(255,255,255,0.1); padding-bottom:0.8rem;">
                                <div class="mod-report-name" style="font-weight:bold; font-size:1.1rem;">${mod.nickname || 'Без ника'}</div>
                                <div style="color:var(--color-success); font-weight:bold;">${mod.calculatedRealXp} Real XP</div>
                            </div>
                            <div class="mod-report-days" style="display:flex; gap:0.5rem; overflow-x:auto; padding-top:0.8rem; padding-bottom:0.5rem;">`;
                
                sortedDates.forEach(d => {
                    const rep = (reports || []).find(r => r.date && r.date.toLowerCase().includes((mod.nickname || '').toLowerCase()) && r.date.includes(d));
                    
                    let isInactiveDay = false;
                    if(inactives) {
                        inactives.forEach(ina => {
                            if(ina.date.toLowerCase().includes((mod.nickname || '').toLowerCase())) {
                                const fromMatch = ina.date.match(/С:\s*([\d-]+)/); const toMatch = ina.date.match(/По:\s*([\d-]+)/);
                                if(fromMatch && toMatch) {
                                    const dateObj = new Date(d);
                                    if(dateObj >= new Date(fromMatch[1]) && dateObj <= new Date(toMatch[1])) isInactiveDay = true;
                                }
                            }
                        });
                    }
                    
                    let currentStatus = 'none';
                    if (rep) currentStatus = rep.status;
                    else if (isInactiveDay) currentStatus = 'Неактив';
                    else {
                        const colDateObj = new Date(d); colDateObj.setHours(0,0,0,0);
                        if (colDateObj < actualDateObj) currentStatus = 'Нет отчета';
                    }

                    let shortDate = d.slice(5).split('-').reverse().join('.');
                    let statusClass = 'status-none';
                    if (currentStatus === 'Норма' || currentStatus === 'Перенорма' || currentStatus === 'Натяг') statusClass = 'status-good';
                    if (currentStatus === 'Герой дня') statusClass = 'status-hero';
                    if (currentStatus === 'Неактив') statusClass = 'status-inactive';
                    if (currentStatus === 'Нет отчета' || currentStatus === 'Не засчитано' || currentStatus === 'Отказ') statusClass = 'status-missing';

                    let displayStatus = currentStatus === 'none' ? 'На проверке' : currentStatus;
                    if (currentStatus === 'Не засчитано') displayStatus = 'Отказ';
                    
                    if (isLeader) {
                        html += `<div class="report-day-item ${statusClass}" style="min-width:130px; background:rgba(0,0,0,0.4); padding:0.8rem; border-radius:12px; display:flex; flex-direction:column; align-items:center; border:1px solid rgba(255,255,255,0.05);">
                                    <div class="report-day-date" style="font-size:0.8rem; margin-bottom:0.5rem; color:#fff; font-weight:bold;">${shortDate}</div>
                                    <select class="status-select ${statusClass}" onchange="updateReportStatusDirectly(this, '${mod.nickname}', '${d}', '${rep ? rep.id : ''}')">
                                        <option value="none" ${currentStatus === 'none' ? 'selected' : ''}>-</option>
                                        <option value="Норма" ${currentStatus === 'Норма' ? 'selected' : ''}>Норма</option>
                                        <option value="Перенорма" ${currentStatus === 'Перенорма' ? 'selected' : ''}>Перенорма</option>
                                        <option value="Натяг" ${currentStatus === 'Натяг' ? 'selected' : ''}>Натяг</option>
                                        <option value="Герой дня" ${currentStatus === 'Герой дня' ? 'selected' : ''}>Натяг</option>
                                        <option value="Неактив" ${currentStatus === 'Неактив' ? 'selected' : ''}>Неактив</option>
                                        <option value="Нет отчета" ${currentStatus === 'Нет отчета' ? 'selected' : ''}>Нет отчета</option>
                                        <option value="Не засчитано" ${(currentStatus === 'Отказ' || currentStatus === 'Не засчитано') ? 'selected' : ''}>Отказ</option>
                                    </select>
                                 </div>`;
                    } else {
                        html += `<div class="report-day-item ${statusClass}" style="min-width:120px; background:rgba(0,0,0,0.4); padding:0.8rem; border-radius:12px; display:flex; flex-direction:column; align-items:center; border:1px solid rgba(255,255,255,0.05);">
                                    <div class="report-day-date" style="font-size:0.8rem; margin-bottom:0.5rem; color:#fff; font-weight:bold;">${shortDate}</div>
                                    <div style="font-weight:bold; font-size:0.85rem; text-align:center;">${displayStatus}</div>
                                 </div>`;
                    }
                });
                html += `</div></div>`;
            });
            html += '</div>'; listArea.innerHTML = html;
        }

        window.updateReportStatusDirectly = async function(selectEl, nick, date, existingId) {
            const val = selectEl.value; 
            
            let statusClass = 'status-none';
            if (val === 'Норма' || val === 'Перенорма') statusClass = 'status-good';
            if (val === 'Герой дня') statusClass = 'status-hero';
            if (val === 'Неактив') statusClass = 'status-inactive';
            if (val === 'Нет отчета' || val === 'Не засчитано' || val === 'Отказ') statusClass = 'status-missing';
            selectEl.className = `status-select ${statusClass}`;
            
            let xpAmount = 0; if(val === 'Норма') xpAmount = 15; if(val === 'Перенорма') xpAmount = 30; if(val === 'Натяг') xpAmount = 7; if(val === 'Герой дня') xpAmount = 60;
            
            selectEl.style.opacity = '0.5'; selectEl.disabled = true;

            if (existingId) {
                if (val === 'none') { await supa.from('reports').delete().eq('id', existingId); selectEl.setAttribute('onchange', `updateReportStatusDirectly(this, '${nick}', '${date}', '')`); } 
                else { await supa.from('reports').update({ status: val, xp: xpAmount }).eq('id', existingId); }
            } else {
                if (val !== 'none') {
                    const fakeData = `Ник: ${nick} | Дата: ${date} | Работа: Выставлено руководством`;
                    const newId = 'rep_manual_' + Date.now().toString();
                    await supa.from('reports').insert([{ id: newId, email: currentUser.email, link: '', date: fakeData, status: val, xp: xpAmount }]);
                    selectEl.setAttribute('onchange', `updateReportStatusDirectly(this, '${nick}', '${date}', '${newId}')`);
                }
            }
            if (val === 'Не засчитано' || val === 'Нет отчета') { selectEl.style.borderColor = '#ef4444'; selectEl.style.color = '#ef4444'; } else { selectEl.style.borderColor = ''; selectEl.style.color = ''; }
            selectEl.style.opacity = '1'; selectEl.disabled = false;
            
            setTimeout(() => { loadReportsTable(); loadCreatorPanelData(); }, 1000);
        };

        window.processReport = async function(id, statusText, xpAmount) { 
            await supa.from('reports').update({ status: statusText, xp: xpAmount }).eq('id', id); document.getElementById('viewReportsBtn').click(); setTimeout(() => document.getElementById('viewReportsBtn').click(), 100); 
        };
        
        window.processInactive = async function(id, statusText) { 
            await supa.from('reports').update({ status: statusText }).eq('id', id); document.getElementById('viewInactivesBtn').click(); setTimeout(() => document.getElementById('viewInactivesBtn').click(), 100); 
        };

        // Подключаем кнопки
        const getEl = (id) => document.getElementById(id);
        
        getEl('loginBtnUI').onclick = () => { getEl('authModal').style.display = 'flex'; getEl('authErrorMsg').style.display = 'none'; };
        getEl('authCloseModal').onclick = () => { getEl('authModal').style.display = 'none'; };
        getEl('logoutBtnUI').onclick = async () => { await supa.auth.signOut(); location.reload(); };

        getEl('authLoginSubmit').onclick = async () => {
            const email = getEl('authEmail').value, password = getEl('authPassword').value, err = getEl('authErrorMsg');
            if(!email || !password) { err.textContent = "Введите Email и Пароль!"; err.style.display = 'block'; return; }
            err.textContent = "Загрузка..."; err.style.color = "var(--color-primary)"; err.style.display = 'block';
            const { error } = await supa.auth.signInWithPassword({ email, password });
            if(error) { err.textContent = error.message; err.style.color = "var(--color-error)"; } else { window.location.reload(); }
        };

        getEl('authRegisterSubmit').onclick = async () => {
            const email = getEl('authEmail').value, nickname = getEl('authNickname').value, password = getEl('authPassword').value, err = getEl('authErrorMsg');
            if(!email || !password || !nickname) { err.textContent = "Заполните все поля, включая Никнейм!"; err.style.color = "var(--color-error)"; err.style.display = 'block'; return; }
            err.textContent = "Загрузка..."; err.style.color = "var(--color-primary)"; err.style.display = 'block';
            const { error } = await supa.auth.signUp({ email, password, options: { data: { nickname: nickname } } });
            if(error) { err.textContent = error.message; err.style.color = "var(--color-error)"; } 
            else { err.textContent = "Успешно! Теперь войдите."; err.style.color = "var(--color-success)"; }
        };

        getEl('forceNicknameBtn')?.addEventListener('click', async () => {
            const val = getEl('forceNicknameInput').value.trim(); if (val.length < 3) return alert("Никнейм должен быть длиннее 3 символов!");
            await supa.auth.updateUser({ data: { nickname: val } }); if (currentUser) await supa.from('user_stats').update({ nickname: val }).eq('user_id', currentUser.id);
            currentNickname = val; getEl('userEmailDisplay').textContent = val; getEl('nicknameModal').style.display = 'none'; 
            if(!state.started && getEl("authorName")?.textContent === "System") startGame();
        });

        document.querySelectorAll('[data-action]').forEach(btn => { btn.onclick = () => judge(btn.dataset.action); });
        document.querySelectorAll('[data-comp-action]').forEach(btn => { btn.onclick = () => judgeComplaint(btn.dataset.compAction); });
        
        const sb = getEl('startBtn'); if (sb) sb.onclick = startGame;
        const rb = getEl('resetBtn'); if (rb) rb.onclick = resetGame;
        
        const themeBtn = document.querySelector('[data-theme-toggle]');
        if(themeBtn) { 
            themeBtn.onclick = () => { 
                const root = document.documentElement;
                if(root.getAttribute('data-theme') === 'dark') { root.setAttribute('data-theme', 'light'); themeBtn.textContent = '☀️'; } 
                else { root.setAttribute('data-theme', 'dark'); themeBtn.textContent = '🌙'; } 
            };
        }

        // Кнопки панелей
        getEl('equipCrownBtn')?.addEventListener('click', () => { activeCosmetics.crown = !activeCosmetics.crown; localStorage.setItem('userCosmetics', JSON.stringify(activeCosmetics)); renderProfileData(); });
        getEl('equipColorBtn')?.addEventListener('click', () => { activeCosmetics.color = !activeCosmetics.color; localStorage.setItem('userCosmetics', JSON.stringify(activeCosmetics)); renderProfileData(); });
        
        getEl('lbBtnMod')?.addEventListener('click', () => { getEl('leaderboardList').innerHTML = window.lbModHTML || '<div class="message-text">Топ Модерации пуст.</div>'; getEl('lbBtnMod').className="btn btn-primary"; getEl('lbBtnAp').className="btn btn-secondary"; });
        getEl('lbBtnAp')?.addEventListener('click', () => { getEl('leaderboardList').innerHTML = window.lbApHTML || '<div class="message-text">Топ АП пуст.</div>'; getEl('lbBtnAp').className="btn btn-primary"; getEl('lbBtnMod').className="btn btn-secondary"; });

        getEl('supportCheckBtn')?.addEventListener('click', () => {
            if (supportState.currentIndex < 0) return;
            let combinedSupQuestions = [...baseSupQuestions, ...customSupQuestions];
            const q = combinedSupQuestions[supportState.currentIndex], answer = getEl("supportAnswerInput").value.trim().toLowerCase(), resEl = getEl("supportResultText");
            if (!answer) { resEl.textContent = "Напиши ответ игроку."; return; }
            supportState.resolved++; 
            const ok = q.keywords.some(k => answer.includes(k));
            if (ok) { supportState.correct++; resEl.textContent = "Ответ засчитан!"; resEl.style.color = "var(--color-success)"; playSound('ok'); pushLog(`🟢 АП: ответ засчитан.`); } 
            else { supportState.mistakes++; resEl.textContent = "Ответ не засчитан: не хватает ключевых слов или команды."; resEl.style.color = "var(--color-error)"; playSound('fail'); pushLog(`🔴 АП: ответ не засчитан.`); }
            updateSupportStats(); saveProgress();
        });

        getEl('supportNextBtn')?.addEventListener('click', () => {
            let combinedSupQuestions = [...baseSupQuestions, ...customSupQuestions];
            if (supQueue.length === 0) { supQueue = combinedSupQuestions.map((_, i) => i); shuffleArray(supQueue); }
            supportState.currentIndex = supQueue.pop(); const q = combinedSupQuestions[supportState.currentIndex];
            getEl("supportQuestionTitle").textContent = q.title; getEl("supportQuestionText").textContent = q.text; getEl("supportAnswerInput").value = ""; getEl("supportResultText").textContent = "";
        });

        getEl('taStartBtn')?.addEventListener('click', () => {
            getEl('taStartScreen').style.display = 'none'; getEl('taGameScreen').style.display = 'grid';
            taTimeLeft = 60; taState.score = 0; taState.mistakes = 0; updateTaUI(); taNextMsg(); clearInterval(taTimerInt);
            taTimerInt = setInterval(() => { taTimeLeft--; updateTaUI(); if(taTimeLeft <= 0) endTaGame(); }, 1000);
        });

        document.querySelectorAll('[data-ta-action]').forEach(btn => {
            btn.addEventListener('click', () => {
                if(!taState.current || taTimeLeft <= 0) return;
                const action = btn.dataset.taAction;
                if(action === taState.current.type) { taState.score++; playSound('ok'); } else { taState.mistakes++; taTimeLeft -= 3; playSound('fail'); const timerEl = getEl('taTimer'); timerEl.classList.add('danger'); setTimeout(() => timerEl.classList.remove('danger'), 500); }
                taNextMsg(); updateTaUI();
            });
        });

