        function escapeHtmlFix(value) {
            return String(value ?? '').replace(/[&<>"']/g, ch => ({ '&':'&amp;', '<':'&lt;', '>':'&gt;', '"':'&quot;', "'":'&#039;' }[ch]));
        }
        function makeFixId(prefix) { return prefix + '_' + Date.now() + '_' + Math.random().toString(36).slice(2); }
        function bindPress(el, handler) {
            if (!el || el.dataset.pressBound === '1') return;
            el.dataset.pressBound = '1';
            const wrapped = (event) => {
                if (el.disabled) return;
                if (event && typeof event.preventDefault === 'function') event.preventDefault();
                handler(event);
            };
            if (window.PointerEvent) el.addEventListener('pointerup', wrapped, { passive: false });
            else el.addEventListener('click', wrapped, { passive: false });
        }
        function replaceAndBindButton(id, handler) {
            const oldBtn = document.getElementById(id);
            if (!oldBtn) return null;
            const newBtn = oldBtn.cloneNode(true);
            oldBtn.replaceWith(newBtn);
            bindPress(newBtn, handler);
            return newBtn;
        }
