            if (!document.getElementById('gossStaffModal')) document.body.insertAdjacentHTML('beforeend', '<div id="gossStaffModal" class="fix-modal-backdrop"><div class="fix-modal-card"><h3 id="gossStaffTitle">Старший состав</h3><p id="gossStaffHint" style="color:var(--color-text-muted); margin-bottom:1rem;">Заполните данные старшего состава.</p><div id="gossStaffRows"></div><div class="fix-modal-actions"><button id="gossStaffAddRowBtn" class="btn btn-secondary" type="button">➕ Добавить строку</button><button id="gossStaffSaveBtn" class="btn btn-primary" type="button">💾 Сохранить</button><button id="gossStaffCloseBtn" class="btn btn-secondary" type="button">Закрыть</button></div></div></div>');

            if (!allModesList.includes('fsb_admin_log')) allModesList.push('fsb_admin_log');
