            async function saveProfileV3(){
                const modal = document.getElementById('gossProfileModal'); if (!modal || !currentUser) return;
                const org = findGossOrg(modal.dataset.org || selectedOrgV3);
                const payload = { nick:document.getElementById('gossProfileNick').value.trim(), post:document.getElementById('gossProfilePost').value.trim(), age:document.getElementById('gossProfileAge').value.trim(), forum:document.getElementById('gossProfileForum').value.trim(), vk:document.getElementById('gossProfileVk').value.trim(), discord:document.getElementById('gossProfileDiscord').value.trim(), appointed:document.getElementById('gossProfileAppointed').value.trim(), timezone:document.getElementById('gossProfileTimezone').value.trim(), org:org.short };
                if (!payload.nick || !payload.post) { alert('Заполните минимум ник и должность.'); return; }
                const { data: old } = await supa.from('reports').select('id').eq('email','GOSS_PROFILE').eq('link',org.id).eq('status',currentUser.id).order('id',{ascending:false}).limit(1);
                if (old && old[0]) await supa.from('reports').update({ date:JSON.stringify(payload), xp:0 }).eq('id', old[0].id);
                else await supa.from('reports').insert([{ id:makeFixId('gossprofile'), email:'GOSS_PROFILE', link:org.id, status:currentUser.id, date:JSON.stringify(payload), xp:0 }]);
                modal.style.display = 'none'; selectedOrgV3 = org.id; selectedViewV3 = isGossLeaderV3(org.id) ? 'staff' : 'profile'; await renderDashboardV3();
            }
