        function applyTambovModeHeaderV7(mode) {
            const brandSub = document.getElementById("brandSubtitle");
            const hTitle = document.getElementById("heroTitle");
            const hText = document.getElementById("heroText");
            const hBadge = document.getElementById("heroBadge2");
            let header = T73_MODE_HEADERS_FROM_REFERENCE[mode];
            if (!header && typeof getDynamicModeHeader === 'function') header = getDynamicModeHeader(mode);
            if (!header && String(mode || '').startsWith('goss_')) {
                const orgId = String(mode).replace('goss_', '');
                const org = (typeof GOSS_ORGS !== 'undefined' ? GOSS_ORGS.find(o => o.id === orgId) : null) || { icon:'🏛️', short:'ГОСС', name:'Государственная организация' };
                header = ["ГОСС: " + org.short, org.icon + ' Тренажёр <span>' + org.short + '</span>.', "Ситуации и рабочие разделы организации: " + org.name + ".", "Режим: " + org.short];
            }
            if (!header) return;
            if (brandSub) brandSub.textContent = header[0];
            if (hTitle) hTitle.innerHTML = header[1];
            if (hText) hText.textContent = header[2];
            if (hBadge) hBadge.textContent = header[3];
            if (typeof updateModeIdentity === 'function') updateModeIdentity(mode, header);
            document.title = header[0] + " — Cherepovets 89";
        }

