                try{ const role=await supa.from('reports').select('*').eq('email','USER_ROLE').eq('status','moderator'); const ids=(role.data||[]).map(r=>r.link).filter(Boolean); if(ids.length){ const us=await supa.from('user_stats').select('user_id,nickname,email').in('user_id',ids.slice(0,350)); (us.data||[]).forEach(u=>{ members[u.user_id||u.email||u.nickname]=u; }); } }catch(e){}
