                        html+='<div class="t73-v14-label">Отчётность</div><select class="t73-v14-select" data-sec1 '+(canEdit?'':'disabled')+' onchange="t73V14SaveTableCell(this)">'+opt14('','—',sec1)+opt14('Норма','Норма',sec1)+opt14('Перенорма','Перенорма',sec1)+opt14('Натяг','Натяг',sec1)+opt14('Герой дня','Герой дня',sec1)+opt14('Отказ','Отказ',sec1)+opt14('Нет отчета','Нет отчета',sec1)+opt14('На проверке','На проверке',sec1)+'</select>';
