                        html+='<div class="t73-v14-mini">'+(rep?('Заявлено: '+esc14(rep.quality||'—')+'<br>Скринов: '+proofs.length):'Отчета нет')+'</div>';
                        if(proofs.length) html+='<div style="display:flex;flex-wrap:wrap;gap:.25rem;">'+proofs.slice(0,isPhone()?2:4).map((p,i)=>'<a class="badge" target="_blank" rel="noreferrer" href="'+esc14(p.url||p)+'">Скрин '+(i+1)+'</a>').join('')+'</div>';
                        html+='<div class="t73-v14-save" data-save></div></div>';
