            ['reportsTableBtn','reportsTableBtnModStatic','v16ReportTableBtnMod','v16ReportTableBtnGen','v16OpenTableTop'].forEach(id=>{const b=$(id); if(b){b.style.display='inline-flex'; b.onclick=e=>{e.preventDefault();showTable();}}});
