          function showReport(){visibleButtons();installUpload();showOnly('report');const w=$('reportAccessWarning'),a=$('reportFormArea'); if(w)w.style.display='none'; if(a)a.style.display='flex';$('mode-report')?.scrollIntoView({behavior:'smooth',block:'start'});}
          function weekDays(){const b=new Date();const day=b.getDay()||7;b.setDate(b.getDate()-day+1-week*7);return Array.from({length:7},(_,i)=>{const d=new Date(b);d.setDate(b.getDate()+i);return d.toISOString().slice(0,10)})}
          function h(d){return new Date(d+'T00:00:00').toLocaleDateString('ru-RU',{day:'2-digit',month:'2-digit'})}
          async function getMembers(days){const m=new Map(),put=o=>{const k=String(o.key||o.userId||o.id||o.email||o.name||'').trim(); if(k)m.set(k,{...(m.get(k)||{}),...o,key:k})};try{const r=await supa.from('user_stats').select('user_id,nickname,email').limit(1500);(r.data||[]).forEach(u=>put({key:u.user_id,userId:u.user_id,name:u.nickname||u.email,email:u.email}))}catch(e){}try{const r=await supa.from('reports').select('*').eq('email',MEMBER).limit(700);(r.data||[]).forEach(x=>{const p=parse(x.status,{});put({key:x.link,name:p.name||x.link,email:p.email||''})})}catch(e){}try{const r=await supa.from('reports').select('*').limit(2500);(r.data||[]).forEach(row=>{if([MARK,MEMBER,'ACCESS_KEY','ADMIN_ROLE','SHOP_MOD','SHOP_AP','SHOP_FSB','GAME_XP','USER_ROLE','INACTIVE_REQ','GOSS_PROFILE'].includes(row.email))return;const p=parse(row.date,{});const d=p.day||(/^\d{4}-\d{2}-\d{2}$/.test(String(row.date||''))?row.date:'');if(d&&days.includes(d))put({key:p.userId||row.email,name:p.nick||row.email,email:row.email,userId:p.userId})})}catch(e){}return [...m.values()].sort((a,b)=>String(a.name||'').localeCompare(String(b.name||''),'ru'))}
          async function getMarks(){const m=new Map();try{const r=await supa.from('reports').select('*').eq('email',MARK).limit(3000);(r.data||[]).forEach(x=>m.set(String(x.link)+'|'+String(x.date),parse(x.status,{})))}catch(e){}return m}
          async function getProofs(days){const m=new Map();try{const r=await supa.from('reports').select('*').limit(2500);(r.data||[]).forEach(row=>{if([MARK,MEMBER,'ACCESS_KEY','ADMIN_ROLE','SHOP_MOD','SHOP_AP','SHOP_FSB','GAME_XP','USER_ROLE','INACTIVE_REQ'].includes(row.email))return;const p=parse(row.date,{});const d=p.day||(/^\d{4}-\d{2}-\d{2}$/.test(String(row.date||''))?row.date:'');if(!days.includes(d))return;let proofs=Array.isArray(p.proofs)?p.proofs:[];if(!proofs.length&&String(row.link||'').startsWith('T73V16:'))proofs=parse(String(row.link).slice(6),[]);else if(!proofs.length&&row.link)proofs=[{url:row.link}];const key=String(p.userId||row.email||p.nick||row.id)+'|'+d;const arr=m.get(key)||[];arr.push({q:p.quality||row.status||'На проверке',n:proofs.length,proofs});m.set(key,arr)})}catch(e){}return m}
          loadReportsTable=async function(){style();const wrap=$('reportsTableWrapper'),lbl=$('rtCurrentWeekLabel');if(!wrap)return;const days=weekDays();if(lbl)lbl.textContent=h(days[0])+' — '+h(days[6]);wrap.innerHTML='<div class="message-card">Загружаю таблицу...</div>';const [members,marks,proofs]=await Promise.all([getMembers(days),getMarks(),getProofs(days)]);const edit=canEdit();const rOpt=['Нет отчета','Норма','Перенорма','Натяг','Герой дня','Отказ','На проверке'],dOpt=['Проверить','Сдано','Неактив','Нет отчета','Освобождён','Отказ'];let top='<div class="v16-openbar"><button class="btn btn-secondary" id="v16Prev" type="button">⬅️ Прошлая неделя</button><button class="btn btn-secondary" id="v16This" type="button">Текущая</button><button class="btn btn-secondary" id="v16Next" type="button">Следующая ➡️</button><input id="v16Manual" class="support-input" placeholder="Добавить Nick_Name"><button class="btn btn-primary" id="v16Add" type="button">➕ Добавить</button></div><div class="v16-small">Редактирование: <b>'+(edit?'доступно':'только руководство')+'</b>. Изменяются два раздела: отчётность и отметка дня.</div>'; if(!members.length){wrap.innerHTML=top+'<div class="message-card">Строк нет. Добавьте ник вручную.</div>';return;}wrap.innerHTML=top+'<div class="v16-table-box">'+members.slice(0,260).map(u=>`<div class="v16-row"><div class="v16-user"><b>${esc(u.name||u.email||u.key)}</b><div class="v16-small">${esc(u.email||u.key)}</div></div><div class="v16-days">${days.map(day=>{const mark=marks.get(u.key+'|'+day)||{};const pf=proofs.get(u.key+'|'+day)||[];const ph=pf.length?pf.map(p=>`<span class="v16-pill">📎 ${esc(p.q)} · ${p.n}</span>`).join(''):'<span class="v16-small">Скринов нет</span>';return `<div class="v16-day"><div class="v16-title">${h(day)}</div><label class="v16-small">Отчётность<select class="v16-select v16mark" data-user="${esc(u.key)}" data-day="${day}" data-k="report" ${edit?'':'disabled'}>${rOpt.map(o=>`<option ${String(mark.report||'Нет отчета')===o?'selected':''}>${o}</option>`).join('')}</select></label><label class="v16-small">Отметка дня<select class="v16-select v16mark" data-user="${esc(u.key)}" data-day="${day}" data-k="day" ${edit?'':'disabled'}>${dOpt.map(o=>`<option ${String(mark.day||'Проверить')===o?'selected':''}>${o}</option>`).join('')}</select></label><input class="v16-note" data-user="${esc(u.key)}" data-day="${day}" value="${esc(mark.note||'')}" placeholder="Комментарий" ${edit?'':'disabled'}>${ph}</div>`}).join('')}</div></div>`).join('')+'</div>';};
          async function saveMark(user,day){if(!canEdit())return alert('Менять таблицу может только руководство.');const card=document.querySelector(`.v16mark[data-user="${CSS.escape(user)}"][data-day="${CSS.escape(day)}"]`)?.closest('.v16-day');const payload={report:card?.querySelector('[data-k="report"]')?.value||'Нет отчета',day:card?.querySelector('[data-k="day"]')?.value||'Проверить',note:card?.querySelector('.v16-note')?.value||'',by:currentUser?.email||'',at:new Date().toISOString()};try{await supa.from('reports').delete().eq('email',MARK).eq('link',user).eq('date',day)}catch(e){}await supa.from('reports').insert([{id:'mark16_'+Date.now()+Math.random(),email:MARK,link:user,date:day,status:JSON.stringify(payload),xp:0}]);}
          async function addMember(){if(!canEdit())return alert('Добавлять строки может только руководство.');const inp=$('v16Manual'),name=String(inp?.value||'').trim();if(!name)return;await supa.from('reports').insert([{id:'mem16_'+Date.now()+Math.random(),email:MEMBER,link:'manual_'+name.toLowerCase().replace(/[^a-zа-я0-9_]+/gi,'_'),date:new Date().toISOString().slice(0,10),status:JSON.stringify({name}),xp:0}]);inp.value='';loadReportsTable();}
          function installUpload(){style();const input=$('reportFileInput');if(!input)return;input.multiple=true;input.accept='image/*,.png,.jpg,.jpeg,.webp';input.closest('.admin-field')?.classList.add('v16-filebox');if(!$('v16UploadNotice'))input.insertAdjacentHTML('beforebegin','<div id="v16UploadNotice" class="v16-small" style="padding:.8rem;border:1px solid rgba(82,199,123,.4);border-radius:12px;background:rgba(82,199,123,.1);color:#d8ffe4"><b>📎 Прямая загрузка включена:</b> можно выбрать много скриншотов сразу.</div>');let prev=$('reportFilePreview');if(prev)prev.className='v16-preview';input.onchange=()=>{selectedFiles=selectedFiles.concat([...input.files].filter(f=>/^image\//.test(f.type))).slice(0,/iPhone|Android/i.test(navigator.userAgent)?12:30);input.value='';renderPrev()};const old=$('submitReportBtn');if(old&&!$('submitReportBtnV16')){old.style.display='none';old.insertAdjacentHTML('afterend','<button class="support-check-btn" type="button" id="submitReportBtnV16" style="margin-top:1rem;width:100%;background:linear-gradient(135deg,#52c77b,#8fe0a8);color:#08110b">📎 Отправить отчет с файлами</button>')}const b=$('submitReportBtnV16');if(b)b.onclick=submitReport;renderPrev()}
          function renderPrev(){const p=$('reportFilePreview');if(!p)return;p.innerHTML=selectedFiles.length?selectedFiles.map((f,i)=>`<div class="v16-file"><button type="button" data-rm="${i}">×</button><img src="${URL.createObjectURL(f)}"><div class="v16-small">${esc(f.name)}<br>${Math.round(f.size/1024)} KB</div></div>`).join(''):'<div class="v16-small">Файлы ещё не выбраны.</div>';p.querySelectorAll('[data-rm]').forEach(b=>b.onclick=()=>{selectedFiles.splice(+b.dataset.rm,1);renderPrev()})}
          async function compress(f){const data=await new Promise(r=>{const rd=new FileReader();rd.onload=()=>r(rd.result);rd.readAsDataURL(f)});const img=await new Promise(r=>{const im=new Image();im.onload=()=>r(im);im.src=data});let w=img.width,h=img.height,max=/iPhone|Android/i.test(navigator.userAgent)?900:1280;if(w>h&&w>max){h=Math.round(h*max/w);w=max}else if(h>w&&h>max){w=Math.round(w*max/h);h=max}const c=document.createElement('canvas');c.width=w;c.height=h;c.getContext('2d').drawImage(img,0,0,w,h);const blob=await new Promise(r=>c.toBlob(r,'image/jpeg',.62));return{blob,fallback:c.toDataURL('image/jpeg',.55)}}
