          async function submitReport(){const res=$('reportResultText'),btn=$('submitReportBtnV16');const nick=($('reportNickInput')?.value||currentNickname||'').trim(),work=($('reportWorkInput')?.value||'').trim(),day=$('reportDateInput')?.value||new Date().toISOString().slice(0,10),quality=$('reportQualityInput')?.value||'На проверке',link=($('reportLinkInput')?.value||'').trim();if(!currentUser){res.textContent='Войдите в аккаунт.';return}if(!nick||!work){res.textContent='Заполните ник и работу.';return}if(!link&&!selectedFiles.length){res.textContent='Добавьте ссылку или скриншоты.';return}btn.disabled=true;btn.textContent='Загружаю...';const proofs=[];if(link)proofs.push({url:link,name:'Ссылка'});for(let i=0;i<selectedFiles.length;i++)proofs.push(await up(selectedFiles[i],i));const payload={version:'v16',nick,work,day,quality,proofs,userId:currentUser.id,email:currentUser.email};const {error}=await supa.from('reports').insert([{id:'rep16_'+Date.now()+Math.random(),email:currentUser.email,link:'T73V16:'+JSON.stringify(proofs.map(p=>({url:p.url,name:p.name,bucket:p.bucket||'',fallback:!!p.fallback}))),date:JSON.stringify(payload),status:'На проверке',xp:0}]);btn.disabled=false;btn.textContent='📎 Отправить отчет с файлами';if(error){res.style.color='var(--color-error)';res.textContent='Ошибка: '+error.message}else{selectedFiles=[];renderPrev();res.style.color='var(--color-success)';res.textContent='✅ Отчет отправлен. Файлов: '+proofs.length}}
