            const { data: modRoles } = await supa.from('reports').select('link').eq('email','USER_ROLE').eq('status','moderator'); const modIds = (modRoles || []).map(r => r.link).filter(Boolean); if(modIds.length === 0){ listArea.innerHTML = '<div class="message-text" style="text-align:center;">Модераторы не найдены. Выдайте кому-нибудь роль.</div>'; return; }
            const { data: usersData } = await supa.from('user_stats').select('user_id,nickname,email,shop_spent').in('user_id', modIds); let mods = usersData || [];
            let sortedDates = []; const today = new Date(); today.setHours(0,0,0,0); today.setDate(today.getDate() - (currentTableWeekOffset * 7)); for(let i=0;i<7;i++){ const d = new Date(today); d.setDate(d.getDate() - i); sortedDates.push(d.toISOString().slice(0,10)); } sortedDates.reverse();
