            if(!leader) mods = mods.filter(m => !(Array.isArray(adminEmails)&&adminEmails.includes(m.email)) && m.email !== creatorEmail && !(Array.isArray(dynamicModLeaders)&&dynamicModLeaders.includes(m.user_id)));
            const actual = new Date(); actual.setHours(0,0,0,0); let html = '<div class="t73-v25-mod-wrap">';
            mods.sort((a,b)=>String(a.nickname||'').localeCompare(String(b.nickname||''),'ru')).forEach(mod => { html += `<div class="t73-v25-mod-card"><div class="t73-v25-mod-head"><div><b>${esc(mod.nickname || 'Без ника')}</b><div style="color:var(--color-text-muted);font-size:.85rem;">${esc(mod.email || '')}</div></div><div style="color:var(--color-success);font-weight:900;">${mod.calculatedRealXp} Real XP</div></div><div class="t73-v25-mod-days">`; sortedDates.forEach(d => { const nick = String(mod.nickname || '').toLowerCase(); const rep = (reports || []).find(r => String(r.date || '').toLowerCase().includes(nick) && String(r.date || '').includes(d)); let inactive = false; (inactives || []).forEach(ina => { const txt = String(ina.date || '').toLowerCase(); if(txt.includes(nick)){ const fm = txt.match(/с:\s*([\d-]+)/i), tm = txt.match(/по:\s*([\d-]+)/i); if(fm && tm){ const dd = new Date(d); if(dd >= new Date(fm[1]) && dd <= new Date(tm[1])) inactive = true; } } }); let st = 'none'; if(rep) st = rep.status; else if(inactive) st = 'Неактив'; else { const cd = new Date(d); cd.setHours(0,0,0,0); if(cd < actual) st = 'Нет отчета'; } const cls = statusClass25(st); const shortDate = d.slice(5).split('-').reverse().join('.'); const display = st === 'none' ? 'На проверке' : (st === 'Не засчитано' ? 'Отказ' : st); if(leader){ html += `<div class="t73-v25-mod-day ${cls}"><div class="t73-v25-date">${shortDate}</div><select class="t73-v25-status-select ${cls}" data-nick="${esc(mod.nickname||'')}" data-date="${d}" data-id="${rep ? esc(rep.id) : ''}"><option value="none" ${st==='none'?'selected':''}>-</option><option value="Норма" ${st==='Норма'?'selected':''}>Норма</option><option value="Перенорма" ${st==='Перенорма'?'selected':''}>Перенорма</option><option value="Герой дня" ${st==='Герой дня'?'selected':''}>Натяг</option><option value="Неактив" ${st==='Неактив'?'selected':''}>Неактив</option><option value="Нет отчета" ${st==='Нет отчета'?'selected':''}>Нет отчета</option><option value="Не засчитано" ${(st==='Отказ'||st==='Не засчитано')?'selected':''}>Отказ</option></select></div>`; } else html += `<div class="t73-v25-mod-day ${cls}"><div class="t73-v25-date">${shortDate}</div><div class="t73-v25-status">${esc(display)}</div></div>`; }); html += '</div></div>'; }); html += '</div>'; listArea.innerHTML = html; listArea.querySelectorAll('.t73-v25-status-select').forEach(sel => sel.onchange = () => window.updateReportStatusDirectly(sel, sel.dataset.nick, sel.dataset.date, sel.dataset.id || ''));
