/* === extracted script: inline === */
/* === T73 V32 HOTFIX: ГОСС/СС без Героя дня, только Натяг === */
(() => {
  if (window.__T73_V32_GOSS_NO_HERO__) return;
  window.__T73_V32_GOSS_NO_HERO__ = true;

  const GOSS_ROOT_SELECTORS = [
    '#gossV3Content',
    '#gossV4Content',
    '#gossOrgPanel',
    '#gossOrgArea',
    '#gossV31ReportsRoot',
    '#gossReportsArea',
    '#v30GossReviewBar',
    '.goss-report-actions-v31',
    '.goss-report-actions-v30',
    '.goss-v4-actions',
    '[data-goss-org]'
  ].join(',');

  function isGossZone(node) {
    if (!node || !node.closest) return false;
    return !!node.closest(GOSS_ROOT_SELECTORS);
  }

  function normalizeGossStatus(status, points) {
    const s = String(status || '').trim();
    if (/герой\s*дня/i.test(s)) return { status: 'Натяг', points: Number(points) > 0 && Number(points) < 60 ? Number(points) : 5 };
    return { status: s, points: Number(points) || 0 };
  }

  function patchOptionSelect(select) {
    if (!select || !isGossZone(select)) return;
    const hasNatyag = Array.from(select.options || []).some(o => String(o.value || o.textContent).trim() === 'Натяг');
    Array.from(select.options || []).forEach(opt => {
      const txt = String(opt.textContent || opt.value || '');
      if (/герой\s*дня/i.test(txt)) {
        if (hasNatyag) opt.remove();
        else {
          opt.value = 'Натяг';
          opt.textContent = 'Натяг';
        }
      }
    });
  }

  function patchGossButton(btn) {
    if (!btn || !isGossZone(btn)) return;
    const txt = String(btn.textContent || '');
    const onclick = String(btn.getAttribute('onclick') || '');
    if (!/герой\s*дня/i.test(txt + ' ' + onclick)) return;

    btn.textContent = txt.replace(/Герой\s*дня/gi, 'Натяг').replace(/\(60\)/g, '(5)');
    btn.setAttribute('data-goss-hero-fixed', '1');

    if (onclick) {
      let fixed = onclick
        .replace(/(['"])Герой\s*дня\1/gi, "'Натяг'")
        .replace(/,\s*60\s*\)/g, ',5)')
        .replace(/,\s*60\s*,/g, ',5,');
      btn.setAttribute('onclick', fixed);
    }
  }

  function patchTextNodes(root) {
    if (!root) return;
    const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, {
      acceptNode(node) {
        if (!node.nodeValue || !/Герой\s*дня/i.test(node.nodeValue)) return NodeFilter.FILTER_REJECT;
        const parent = node.parentElement;
        if (!parent || !isGossZone(parent)) return NodeFilter.FILTER_REJECT;
        return NodeFilter.FILTER_ACCEPT;
      }
    });
    const nodes = [];
    while (walker.nextNode()) nodes.push(walker.currentNode);
    nodes.forEach(n => { n.nodeValue = n.nodeValue.replace(/Герой\s*дня/gi, 'Натяг').replace(/60\s*(балл|XP|xp|очк)/gi, '5 $1'); });
  }

  function patchGossDom() {
    document.querySelectorAll('select').forEach(patchOptionSelect);
    document.querySelectorAll('button, .btn').forEach(patchGossButton);
    document.querySelectorAll('#gossV3Content, #gossV4Content, #gossOrgPanel, #gossOrgArea, #gossV31ReportsRoot, #gossReportsArea, #v30GossReviewBar').forEach(patchTextNodes);
  }

  function wrapGossProcessor(name) {
    const old = window[name];
    if (typeof old !== 'function' || old.__v32Wrapped) return;
    const wrapped = async function(id, status, points, ...rest) {
      const fixed = normalizeGossStatus(status, points);
      return old.call(this, id, fixed.status, fixed.points, ...rest);
    };
    wrapped.__v32Wrapped = true;
    window[name] = wrapped;
  }

  function wrapKnownProcessors() {
    ['processGossReportV31', 'processGossReport30', 'processGossReport29', 'processGossReportV27'].forEach(wrapGossProcessor);
  }

  document.addEventListener('change', (e) => {
    const select = e.target && e.target.closest && e.target.closest('select');
    if (!select || !isGossZone(select)) return;
    patchOptionSelect(select);
    if (/герой\s*дня/i.test(String(select.value || ''))) select.value = 'Натяг';
  }, true);

  document.addEventListener('click', (e) => {
    const btn = e.target && e.target.closest && e.target.closest('button, .btn');
    if (!btn || !isGossZone(btn)) return;
    if (!/герой\s*дня/i.test(String(btn.textContent || '') + ' ' + String(btn.getAttribute('onclick') || ''))) return;
    patchGossButton(btn);
  }, true);

  function boot() {
    wrapKnownProcessors();
    patchGossDom();
  }

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', boot); else boot();
  setTimeout(boot, 300);
  setTimeout(boot, 1000);
  setInterval(() => { wrapKnownProcessors(); patchGossDom(); }, 1800);
  new MutationObserver(() => {
    clearTimeout(window.__t73V32GossPatchTimer);
    window.__t73V32GossPatchTimer = setTimeout(boot, 80);
  }).observe(document.documentElement, { childList: true, subtree: true });
})();


/* === extracted script: inline === */
/* === T73 V33 HOTFIX: модерация = Герой дня, ГОСС/СС = Натяг === */
(() => {
  if (window.__T73_V33_MOD_HERO_DAY__) return;
  window.__T73_V33_MOD_HERO_DAY__ = true;
  const GOSS_ZONE = '#gossV3Content,#gossV4Content,#gossOrgPanel,#gossOrgArea,#gossV31ReportsRoot,#gossReportsArea,#v30GossReviewBar,[data-goss-org]';
  function inGoss(el){ return !!(el && el.closest && el.closest(GOSS_ZONE)); }
  function restore(btn){
    if (!btn || inGoss(btn)) return;
    const on = String(btn.getAttribute('onclick') || '');
    if (!/(processReport|processModReport)/.test(on) || !/Герой\s*дня/i.test(on)) return;
    const t = String(btn.textContent || '').trim();
    if (/натяг/i.test(t) || /^герой$/i.test(t) || /\(5\)/.test(t)) btn.textContent = /\(/.test(t) ? 'Герой дня (60)' : 'Герой дня';
    btn.setAttribute('onclick', on.replace(/,\s*5\s*\)/g, ',60)').replace(/,\s*5\s*,/g, ',60,'));
  }
  function boot(){ document.querySelectorAll('button,.btn').forEach(restore); }
  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', boot); else boot();
  document.addEventListener('click', () => setTimeout(boot, 50), true);
  setTimeout(boot, 300); setTimeout(boot, 1200); setInterval(boot, 1700);
  new MutationObserver(() => { clearTimeout(window.__t73V33ModHeroTimer); window.__t73V33ModHeroTimer = setTimeout(boot, 80); }).observe(document.documentElement, {childList:true, subtree:true});
})();


