/* === extracted script: t73-v56-clean-moderation-tabs-script === */
(function(){
  'use strict';
  if (window.__T73_V56_CLEAN_MOD_REPORTS__) return;
  window.__T73_V56_CLEAN_MOD_REPORTS__ = true;

  const $ = id => document.getElementById(id);
  const qsa = (sel, root = document) => Array.from(root.querySelectorAll(sel));

  const BAD_MOD_IDS = new Set([
    'reportsTableBtnModV15',
    'reportsTableBtnModStatic',
    'v16ReportTableBtnMod',
    'v16ReportBtnMod',
    'v25ModViewReportsBtn'
  ]);

  function normalizeText(value) {
    return String(value || '')
      .replace(/[📊📎✅🧾]/g, '')
      .replace(/ё/g, 'е')
      .trim()
      .toLowerCase();
  }

  function isBadModerationTab(btn) {
    if (!btn) return false;
    if (btn.id === 'reportTabBtn') return false;
    if (BAD_MOD_IDS.has(btn.id)) return true;
    if (btn.dataset && btn.dataset.mode === 'reports_table') return true;

    const txt = normalizeText(btn.textContent);
    const isReportsTable = /таблица\s*отчет/.test(txt) || /просмотр.*отчет/.test(txt) || /просмотреть.*отчет/.test(txt);
    const isSeparateSubmit = /(сдать|сдача)\s*отчет/.test(txt) || /сдать\s*отчетность/.test(txt);
    return isReportsTable || isSeparateSubmit;
  }

  function cleanModerationTabs() {
    const nav = $('subNavModeration');
    if (!nav) return;

    qsa('button', nav).forEach(btn => {
      if (!isBadModerationTab(btn)) return;
      btn.classList.add('t73-v56-hidden-bad-tab');
      btn.setAttribute('aria-hidden', 'true');
      btn.style.setProperty('display', 'none', 'important');
      btn.style.setProperty('visibility', 'hidden', 'important');
      btn.style.setProperty('pointer-events', 'none', 'important');
      btn.onclick = null;
    });
  }

  function keepReportsTableInGeneral() {
    const general = $('subNavGeneral');
    const table = $('reportsTableBtn');
    if (!general || !table) return;

    if (table.parentElement !== general) {
      const before = general.querySelector('[data-mode="guide"]') || general.querySelector('[data-mode="about"]') || null;
      general.insertBefore(table, before);
    }

    table.dataset.mode = 'reports_table';
    table.textContent = '📊 Таблица отчетов';
  }

  function moveReportCheckDown() {
    const form = $('reportFormArea');
    const admin = $('adminPanelArea');
    const list = $('reportsListArea');
    const btn = $('viewReportsBtn');

    if (form && admin) form.appendChild(admin);
    if (form && list) form.appendChild(list);

    if (admin) {
      admin.style.setProperty('width', '100%', 'important');
      admin.style.setProperty('max-width', '100%', 'important');
      admin.style.setProperty('max-height', 'none', 'important');
      admin.style.setProperty('overflow', 'visible', 'important');
      admin.style.setProperty('order', '99', 'important');
      admin.style.setProperty('grid-column', '1 / -1', 'important');
    }

    if (btn) {
      btn.textContent = 'Проверить отчетность';
      btn.style.setProperty('width', '100%', 'important');
      btn.style.setProperty('max-width', '100%', 'important');
      btn.style.setProperty('white-space', 'normal', 'important');
    }

    if (list) {
      list.style.setProperty('width', '100%', 'important');
      list.style.setProperty('max-width', '100%', 'important');
      list.style.setProperty('max-height', 'none', 'important');
      list.style.setProperty('overflow', 'visible', 'important');
      list.style.setProperty('order', '100', 'important');
      list.style.setProperty('grid-column', '1 / -1', 'important');
    }
  }

  function bootV56() {
    cleanModerationTabs();
    keepReportsTableInGeneral();
    moveReportCheckDown();
  }

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', bootV56);
  else bootV56();

  [80, 250, 600, 1200, 2400, 5200].forEach(ms => setTimeout(bootV56, ms));
  document.addEventListener('click', () => setTimeout(bootV56, 60), true);

  new MutationObserver(() => {
    clearTimeout(window.__T73_V56_CLEAN_TIMER__);
    window.__T73_V56_CLEAN_TIMER__ = setTimeout(bootV56, 80);
  }).observe(document.documentElement, { childList: true, subtree: true });

  window.T73_V56_CLEAN_MOD_REPORTS = { boot: bootV56, cleanModerationTabs, keepReportsTableInGeneral, moveReportCheckDown };
})();


/* === extracted script: t73-v57-direct-screenshot-script === */
(function(){
  'use strict';
  if (window.__T73_V57_DIRECT_SCREENSHOT__) return;
  window.__T73_V57_DIRECT_SCREENSHOT__ = true;

  const $ = id => document.getElementById(id);
  const esc = value => String(value ?? '').replace(/[&<>"']/g, s => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[s]));
  let filesV57 = [];
  let busyV57 = false;

  function isImageFile(file) {
    return !!file && (/^image\//i.test(file.type || '') || /\.(png|jpe?g|webp)$/i.test(file.name || ''));
  }

  function ensureUiV57() {
    const input = $('reportFileInput');
    if (!input) return;

    input.setAttribute('multiple', 'multiple');
    input.setAttribute('accept', 'image/*,.png,.jpg,.jpeg,.webp');

    if (!$('t73-v57-upload-note')) {
      input.insertAdjacentHTML('beforebegin', '<div id="t73-v57-upload-note"><b>📎 Прямая загрузка исправлена:</b> выберите скриншот с устройства. Он сожмётся и сохранится прямо в отчёте, без Imgur/Yapx и без обязательного Storage-бакета.</div>');
    }

    if (!$('reportFilePreview')) {
      input.insertAdjacentHTML('afterend', '<div id="reportFilePreview" class="t73-v57-preview"></div>');
    } else {
      $('reportFilePreview').classList.add('t73-v57-preview');
    }

    const oldBtn = $('submitReportBtn');
    const oldV16 = $('submitReportBtnV16');
    if (oldBtn) oldBtn.style.setProperty('display', 'none', 'important');
    if (oldV16) oldV16.style.setProperty('display', 'none', 'important');

    if (!$('submitReportBtnV57')) {
      const place = oldV16 || oldBtn || input;
      place.insertAdjacentHTML('afterend', '<button class="support-check-btn" type="button" id="submitReportBtnV57">📤 Отправить отчёт со скриншотом</button>');
    }

    const btn = $('submitReportBtnV57');
    if (btn) btn.onclick = sendReportV57;
    renderPreviewV57();
  }

  function renderPreviewV57() {
    const box = $('reportFilePreview');
    if (!box) return;
    box.classList.add('t73-v57-preview');
    if (!filesV57.length) {
      box.innerHTML = '<div style="color:var(--color-text-muted);font-size:.86rem;grid-column:1/-1;">Скриншоты пока не выбраны.</div>';
      return;
    }
    box.innerHTML = filesV57.map((file, index) => {
      const url = URL.createObjectURL(file);
      return `<div class="t73-v57-file">
        <button class="t73-v57-remove" type="button" data-v57-remove="${index}">×</button>
        <img src="${url}" alt="Скриншот ${index + 1}" onload="try{URL.revokeObjectURL(this.src)}catch(e){}">
        <div class="t73-v57-file-name">${esc(file.name || ('screen_' + (index + 1)))}</div>
      </div>`;
    }).join('');
    box.querySelectorAll('[data-v57-remove]').forEach(btn => {
      btn.onclick = () => {
        filesV57.splice(Number(btn.dataset.v57Remove), 1);
        renderPreviewV57();
      };
    });
  }

  function handleFileChangeV57(event) {
    const input = event.target && event.target.closest ? event.target.closest('#reportFileInput') : null;
    if (!input) return;
    event.preventDefault();
    event.stopPropagation();
    event.stopImmediatePropagation();

    const incoming = Array.from(input.files || []).filter(isImageFile);
    const limit = /iPhone|Android|Mobile/i.test(navigator.userAgent) ? 8 : 12;
    filesV57 = filesV57.concat(incoming).slice(0, limit);
    input.value = '';
    renderPreviewV57();

    const res = $('reportResultText');
    if (res && incoming.length) {
      res.style.color = 'var(--color-text-muted)';
      res.textContent = 'Выбрано скриншотов: ' + filesV57.length;
    }
  }

  function readAsDataURL(file) {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(String(reader.result || ''));
      reader.onerror = () => reject(reader.error || new Error('Не удалось прочитать файл'));
      reader.readAsDataURL(file);
    });
  }

  function loadImage(dataUrl) {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.onload = () => resolve(img);
      img.onerror = () => reject(new Error('Файл не удалось открыть как изображение'));
      img.src = dataUrl;
    });
  }

  async function compressToBase64V57(file) {
    const original = await readAsDataURL(file);
    const img = await loadImage(original);

    let maxSide = /iPhone|Android|Mobile/i.test(navigator.userAgent) ? 900 : 1100;
    let width = img.naturalWidth || img.width;
    let height = img.naturalHeight || img.height;
    const ratio = Math.min(1, maxSide / Math.max(width, height));
    width = Math.max(1, Math.round(width * ratio));
    height = Math.max(1, Math.round(height * ratio));

    const canvas = document.createElement('canvas');
    canvas.width = width;
    canvas.height = height;
    const ctx = canvas.getContext('2d', { alpha: false });
    ctx.fillStyle = '#111';
    ctx.fillRect(0, 0, width, height);
    ctx.drawImage(img, 0, 0, width, height);

    let quality = 0.66;
    let out = canvas.toDataURL('image/jpeg', quality);

    while (out.length > 420000 && quality > 0.38) {
      quality -= 0.08;
      out = canvas.toDataURL('image/jpeg', quality);
    }

    while (out.length > 520000 && maxSide > 640) {
      maxSide -= 160;
      const r2 = Math.min(1, maxSide / Math.max(img.naturalWidth || img.width, img.naturalHeight || img.height));
      canvas.width = Math.max(1, Math.round((img.naturalWidth || img.width) * r2));
      canvas.height = Math.max(1, Math.round((img.naturalHeight || img.height) * r2));
      const ctx2 = canvas.getContext('2d', { alpha: false });
      ctx2.fillStyle = '#111';
      ctx2.fillRect(0, 0, canvas.width, canvas.height);
      ctx2.drawImage(img, 0, 0, canvas.width, canvas.height);
      out = canvas.toDataURL('image/jpeg', 0.42);
    }

    return {
      url: out,
      name: file.name || 'screenshot.jpg',
      kind: 'direct-base64',
      originalSize: file.size || 0,
      compressedSize: out.length
    };
  }

  async function canSubmitV57() {
    if (!window.currentUser && typeof currentUser === 'undefined') return false;
    const user = window.currentUser || currentUser;
    if (!user) return false;

    try {
      if (typeof creatorEmail !== 'undefined' && user.email === creatorEmail) return true;
      if (typeof adminEmails !== 'undefined' && Array.isArray(adminEmails) && adminEmails.includes(user.email)) return true;
      if (typeof dynamicModLeaders !== 'undefined' && Array.isArray(dynamicModLeaders) && dynamicModLeaders.includes(user.id)) return true;
      if (typeof isModerator !== 'undefined' && isModerator) return true;
      if (window.supa) {
        const { data } = await supa.from('reports').select('id').eq('email', 'USER_ROLE').eq('link', user.id).eq('status', 'moderator').limit(1);
        return !!(data && data.length);
      }
    } catch (e) {
      return true;
    }
    return true;
  }

  async function sendReportV57(event) {
    if (event) {
      event.preventDefault();
      event.stopPropagation();
      event.stopImmediatePropagation();
    }
    ensureUiV57();
    if (busyV57) return;

    const user = window.currentUser || (typeof currentUser !== 'undefined' ? currentUser : null);
    const res = $('reportResultText');
    const btn = $('submitReportBtnV57');
    const nick = ($('reportNickInput')?.value || (typeof currentNickname !== 'undefined' ? currentNickname : '') || user?.email || '').trim();
    const work = ($('reportWorkInput')?.value || '').trim();
    const day = ($('reportDateInput')?.value || new Date().toISOString().slice(0, 10)).trim();
    const link = ($('reportLinkInput')?.value || '').trim();
    const quality = ($('reportQualityInput')?.value || 'На проверке').trim();

    if (!user) {
      if (res) { res.style.color = 'var(--color-error)'; res.textContent = 'Сначала войдите в аккаунт.'; }
      return;
    }
    if (!(await canSubmitV57())) {
      if (res) { res.style.color = 'var(--color-error)'; res.textContent = 'Сдавать отчёт могут только модераторы.'; }
      return;
    }
    if (!nick || !work || !day) {
      if (res) { res.style.color = 'var(--color-error)'; res.textContent = 'Заполните ник, работу и дату.'; }
      return;
    }
    if (!link && !filesV57.length) {
      if (res) { res.style.color = 'var(--color-error)'; res.textContent = 'Добавьте ссылку или выберите скриншот напрямую.'; }
      return;
    }

    busyV57 = true;
    if (btn) { btn.disabled = true; btn.textContent = '⏳ Обрабатываю скриншоты...'; }
    if (res) { res.style.color = 'var(--color-text-muted)'; res.textContent = 'Сжимаю изображения перед отправкой...'; }

    try {
      const proofs = [];
      if (link) proofs.push({ url: link, name: 'Ссылка', kind: 'link' });

      for (let i = 0; i < filesV57.length; i++) {
        if (res) res.textContent = `Сжимаю скриншот ${i + 1} из ${filesV57.length}...`;
        proofs.push(await compressToBase64V57(filesV57[i]));
      }

      const payload = {
        version: 'v57-direct-screenshot',
        nick,
        nickname: nick,
        work,
        comment: work,
        day,
        date: day,
        quality,
        proofs,
        userId: user.id,
        email: user.email,
        createdAt: new Date().toISOString()
      };

      if (res) res.textContent = 'Отправляю отчёт...';
      const { error } = await supa.from('reports').insert([{
        id: 'rep57_' + Date.now() + '_' + Math.random().toString(16).slice(2),
        email: user.email,
        link: link || 'T73V57:embedded-image',
        date: JSON.stringify(payload),
        status: 'На проверке',
        xp: 0
      }]);

      if (error) throw error;

      filesV57 = [];
      renderPreviewV57();
      ['reportNickInput','reportWorkInput','reportDateInput','reportLinkInput'].forEach(id => { const el = $(id); if (el) el.value = ''; });
      const input = $('reportFileInput'); if (input) input.value = '';
      if ($('reportQualityInput')) $('reportQualityInput').value = 'Норма';

      if (res) { res.style.color = 'var(--color-success)'; res.textContent = '✅ Отчёт отправлен. Скриншоты прикреплены напрямую.'; }
      try { if (typeof playSound === 'function') playSound('win'); } catch (e) {}
    } catch (err) {
      if (res) {
        res.style.color = 'var(--color-error)';
        res.textContent = 'Ошибка отправки: ' + (err?.message || err) + '. Попробуйте выбрать 1 скриншот или отправить ссылку.';
      }
    } finally {
      busyV57 = false;
      if (btn) { btn.disabled = false; btn.textContent = '📤 Отправить отчёт со скриншотом'; }
    }
  }

  document.addEventListener('change', handleFileChangeV57, true);

  document.addEventListener('click', function(event) {
    const submit = event.target.closest?.('#submitReportBtnV57,#submitReportBtn,#submitReportBtnV16');
    if (!submit) return;
    const inReport = submit.closest?.('#mode-report,#reportFormArea');
    if (!inReport) return;
    sendReportV57(event);
  }, true);

  function bootV57() {
    ensureUiV57();
  }

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', bootV57);
  else bootV57();

  [100, 300, 700, 1400, 2600, 5200].forEach(ms => setTimeout(bootV57, ms));
  new MutationObserver(() => {
    clearTimeout(window.__T73_V57_UI_TIMER__);
    window.__T73_V57_UI_TIMER__ = setTimeout(bootV57, 80);
  }).observe(document.documentElement, { childList: true, subtree: true });

  window.T73_V57_DIRECT_SCREENSHOT = { boot: bootV57, send: sendReportV57 };
})();


