  let queueV58 = [];
  let forceDialogNextV58 = false;
  let lastInterceptV58 = 0;
  let lastDownActionV58 = '';
  let lastDownTimeV58 = 0;

  function $(id) { return document.getElementById(id); }
  function escV58(value) {
    return String(value ?? '').replace(/[&<>"']/g, ch => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#039;' }[ch]));
  }
  function ruleInfoV58(id) {
    if (!id || id === 'none') return { id: 'Без правила', text: 'Нарушения нет.', punishment: 'Наказание не требуется' };
    return RULE_MAP_V58[id] || { id, text: 'Правило не найдено в локальной базе.', punishment: 'Проверьте актуальный регламент' };
  }
  function typeLabelV58(type) { return TYPE_LABELS_V58[type] || String(type || 'неизвестно'); }
  function scenarioTitleV58(item) {
    if (item?.title) return item.title;
    if (item?.mode === 'dialog' || Array.isArray(item?.dialog)) return 'Диалоговая ситуация';
    return 'Одиночное сообщение';
  }
  function fallbackExplanationV58(item) {
    if (!item) return 'Ситуация не найдена.';
    if (item.explanation) return item.explanation;
    if (item.rule) {
      const r = ruleInfoV58(item.rule);
      return 'Ситуация относится к правилу ' + r.id + ': ' + r.text;
    }
    if (item.type === 'good') return 'В сообщении нет явного нарушения правил Discord сервера.';
    if (item.type === 'warn') return 'Нарушение относится к лёгкой/средней ветке: устное предупреждение, предупреждение или мут.';
    if (item.type === 'ban') return 'Нарушение относится к тяжёлой ветке: бан, перманентная или глобальная блокировка.';
    return 'Выбирайте вердикт по ближайшему правилу и тяжести нарушения.';
  }
  function normalizeV58(item) {
    const out = Object.assign({}, item || {});
    out.type = out.type || 'good';
    out.rule = out.rule || (out.type === 'good' ? 'none' : '2.1');
    out.explanation = fallbackExplanationV58(out);
    return out;
  }
  function shuffledIndexesV58(arr) {
    const out = arr.map((_, i) => i);
    for (let i = out.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [out[i], out[j]] = [out[j], out[i]];
    }
    return out;
  }
  function combinedCasesV58() {
    let base = [];
    try { if (Array.isArray(baseModMessages)) base = base.concat(baseModMessages); } catch (e) {}
    try { if (Array.isArray(customModMessages)) base = base.concat(customModMessages); } catch (e) {}
    return DISCORD_CASES_V58.concat(base.map(item => normalizeV58(item)));
  }
  function currentUserNameV58() {
    try { if (typeof randomFunnyNick === 'function') return randomFunnyNick(); } catch (e) {}
    return 'Игрок_' + Math.floor(1000 + Math.random() * 9000);
  }
  function initialsV58(name) {
    try { if (typeof initials === 'function') return initials(name); } catch (e) {}
    return String(name || 'T7').split(/[#_\s]+/).filter(Boolean).slice(0, 2).map(part => part[0]).join('').toUpperCase() || 'T7';
  }

