    const client=supaClient(); if(!client){ area.innerHTML='<div class="t73-v94-review-card">Supabase ещё не загрузился.</div>'; return; }
    try{
      const q = client.from('reports').select('*').not('email','in','("ACCESS_KEY","ADMIN_ROLE","SHOP_MOD","SHOP_AP","ROULETTE_MOD","ROULETTE_AP","CUSTOM_MOD_MSG","CUSTOM_AP_MSG","HIDDEN_CHECK","USER_ROLE","INACTIVE_REQ","SHOP_OVERRIDE","GAME_XP","MANUAL_XP","AP_POINTS","FSB_POINTS","FSB_SPEND","SHOP_FSB","ROULETTE_FSB","GOSS_USER_REPORT","GOSS_REPORT_CHECK","GOSS_PROFILE","GOSS_REPORT_TABLE","GOSS_REPORT_TABLE_V13","GOSS_REPORT_TABLE_V15","GOSS_REPORT_TABLE_V16","GOSS_REPORT_TABLE_V19","GOSS_REPORT_MEMBER_V19","GOSS_REPORT_PROOF_V19","GOSS_POINTS_V19","GOSS_ORG_LOG","GOSS_ORG_LOG_V19","GOSS_ORG_LOG_V24","GOSS_SHOP_ITEMS_V13","GOSS_SHOP_ITEMS_V19","GOSS_SHOP_ITEMS_V24","GOSS_SHOP_ITEMS_V26","GOSS_SHOP_PURCHASE","FSB_SHOP_LOG")').order('id',{ascending:false}).limit(80);
      const {data,error}=await withTimeout(q, 12000, 'Не удалось загрузить отчёты'); if(error) throw error;
      const rows=(data||[]).filter(r=>!isService(r));
      if(!rows.length){ area.innerHTML='<div class="t73-v94-review-card">Отчётов пока нет.</div>'; return; }
      area.innerHTML = rows.map(r => {
        const p=parseDatePayload(r), quality=rowQuality(r)||'не выбрано', status=normalizeStatus(r.status||'На проверке'), waiting=status==='На проверке'||status.indexOf('Ожидает')===0;
        const proof = r.link ? (String(r.link).startsWith('data:image') ? `<img src="${r.link}" style="max-width:100%;max-height:170px;border-radius:12px;cursor:zoom-in;border:1px solid rgba(255,255,255,.16);" onclick="document.getElementById('imageModal').style.display='flex';document.getElementById('imageModalSrc').src='${r.link}'">` : `<a class="btn btn-secondary" href="${esc(r.link)}" target="_blank" rel="noreferrer">📎 Открыть доказательство</a>`) : '<span class="t73-v94-chip">Без вложения</span>';
        return `<article class="t73-v94-review-card"><div style="display:flex;justify-content:space-between;gap:.7rem;flex-wrap:wrap;"><div><strong>${esc(p.nick||rowNick(r)||r.email||'Модератор')}</strong><div style="color:var(--color-text-faint);font-size:.82rem;">${esc(p.day||p.date||rowDay(r)||'дата не указана')}</div></div><span class="t73-v94-chip">Выбрал: ${esc(quality)}</span></div><div style="color:var(--color-text-muted);">${esc(p.work||rowText(r))}</div>${proof}<div><span class="t73-v94-chip ${clsFor(status)}">${esc(displayStatus(status))} · ${Number(r.xp||0)} XP</span></div>${waiting?`<div class="t73-v94-review-actions"><button class="btn btn-secondary" style="border-color:#52c77b;color:#52c77b" onclick="processReport('${esc(r.id)}','Норма',15)">Норма</button><button class="btn btn-secondary" style="border-color:#3dd68c;color:#3dd68c" onclick="processReport('${esc(r.id)}','Перенорма',30)">Перенорма</button><button class="btn btn-secondary" style="border-color:#a855f7;color:#c084fc" onclick="processReport('${esc(r.id)}','Натяг',7)">Натяг</button><button class="btn btn-secondary" style="border-color:#3b82f6;color:#60a5fa" onclick="processReport('${esc(r.id)}','Герой дня',60)">Герой дня</button><button class="btn btn-secondary" style="border-color:var(--color-error);color:var(--color-error)" onclick="processReport('${esc(r.id)}','Не засчитано',0)">Отказ</button></div>`:''}</article>`;
      }).join('');
    } catch(e){ area.innerHTML=`<div class="t73-v94-review-card" style="color:var(--color-error);">Ошибка: ${esc(e && e.message || e)}</div>`; }
