  async function processReportV94(id, status, xpAmount){
    if(!isModLeader()){ alert('Проверять отчёты может только руководство.'); return; }
    const client=supaClient(); if(!client){ alert('Supabase ещё не загрузился.'); return; }
    const st=normalizeStatus(status); const r=await client.from('reports').update({status:st, xp:Number(xpAmount ?? xpFor(st))}).eq('id', id);
    if(r.error){ alert('Ошибка: '+r.error.message); return; }
    const area=$('reportsListArea'); if(area){ area.dataset.t73v94Open='0'; }
    setTimeout(showReportsReview, 80);
    if($('mode-reports_table') && getComputedStyle($('mode-reports_table')).display !== 'none') setTimeout(loadReportsTableV94, 250);
  }

  async function submitInactiveV94(){
    const res=$('inactiveResultText');
    if(!hasModAccess()){ if(res){ res.textContent='Неактив доступен только модераторам, руководству и создателю.'; res.style.color='var(--color-error)'; } return; }
    const client=supaClient(); if(!client){ if(res) res.textContent='База ещё не загрузилась.'; return; }
    const nick=String($('inactiveNickInput')?.value || (typeof currentNickname !== 'undefined' ? currentNickname : '') || '').trim();
    const from=String($('inactiveDateFrom')?.value || '').trim();
    const to=String($('inactiveDateTo')?.value || '').trim();
    const reason=String($('inactiveReasonInput')?.value || '').trim();
    if(!nick || !from || !to || !reason){ if(res){ res.textContent='Заполните ник, даты и причину.'; res.style.color='var(--color-error)'; } return; }
    const payload=`Ник: ${nick} | С: ${from} | По: ${to} | Причина: ${reason}`;
    const r=await client.from('reports').insert([{id:'ina_'+Date.now()+'_'+Math.random().toString(16).slice(2), email:'INACTIVE_REQ', link:user()?.email||'', date:payload, status:'Ожидает одобрения', xp:0}]);
    if(r.error){ if(res){ res.textContent='Ошибка: '+r.error.message; res.style.color='var(--color-error)'; } return; }
    if(res){ res.textContent='✅ Заявка на неактив отправлена.'; res.style.color='var(--color-success)'; }
    ['inactiveNickInput','inactiveDateFrom','inactiveDateTo','inactiveReasonInput'].forEach(id=>{ const el=$(id); if(el) el.value=''; });
  }
