  const oldSwitch = window.switchMode;
  window.switchMode = function(mode, btn){
    if(mode === 'reports_table'){ openReportsTable(btn || $('reportsTableBtn')); return; }
    if(['report','inactives','shop'].includes(mode) && !hasModAccess()){
      refreshAccessFromDb(true).then(()=>{ applyAccess(); if(hasModAccess()) window.switchMode(mode, btn); else alert('Этот раздел доступен только модераторам, руководству и создателю.'); }).catch(()=>alert('Этот раздел доступен только модераторам, руководству и создателю.'));
      return;
    }
    if(['guide'].includes(mode) && !anyLeader()){
      refreshAccessFromDb(true).then(()=>{ applyAccess(); if(anyLeader()) window.switchMode(mode, btn); else alert('Раздел «Руководство» доступен только пользователям с выданным доступом.'); }).catch(()=>alert('Раздел «Руководство» доступен только пользователям с выданным доступом.'));
      return;
    }
    if(['leadership','admin_log'].includes(mode) && !isModLeader()){
      refreshAccessFromDb(true).then(()=>{ applyAccess(); if(isModLeader()) window.switchMode(mode, btn); else alert('Раздел доступен только руководству модерации.'); }).catch(()=>alert('Раздел доступен только руководству модерации.'));
      return;
    }
    if(['ap_admin','ap_admin_log'].includes(mode) && !isApLeader()){
      refreshAccessFromDb(true).then(()=>{ applyAccess(); if(isApLeader()) window.switchMode(mode, btn); else alert('Раздел доступен только руководству АП.'); }).catch(()=>alert('Раздел доступен только руководству АП.'));
      return;
    }
    if(['fsb_admin','fsb_admin_log'].includes(mode) && !isFsbLeader()){
      refreshAccessFromDb(true).then(()=>{ applyAccess(); if(isFsbLeader()) window.switchMode(mode, btn); else alert('Раздел доступен только руководству ФСБ.'); }).catch(()=>alert('Раздел доступен только руководству ФСБ.'));
      return;
    }
    const out = typeof oldSwitch === 'function' ? oldSwitch.apply(this, arguments) : undefined;
    setTimeout(run, 80);
    return out;
  };

