(function(){
  'use strict';
  if (window.__T73_VIS_V2__) return;
  window.__T73_VIS_V2__ = true;

  /* Toast-система */
  var cont = document.createElement('div');
  cont.id = 't73-toast-container';
  document.body.appendChild(cont);

  window.t73Toast = function(msg, type, dur){
    type = type || 'ok'; dur = dur || 3200;
    var icons = { ok: '✅', warn: '⚠️', err: '❌', info: 'ℹ️' };
    var t = document.createElement('div');
    t.className = 't73-toast ' + type;
    t.innerHTML = '<span>' + (icons[type]||'💬') + '</span><span>' + msg + '</span>';
    cont.appendChild(t);
    setTimeout(function(){
      t.classList.add('out');
      setTimeout(function(){ if(t.parentNode) t.parentNode.removeChild(t); }, 320);
    }, dur);
  };

  /* Мышиный glow в body::after */
  document.addEventListener('mousemove', function(e){
    var mx = (e.clientX / window.innerWidth * 100).toFixed(1);
    var my = (e.clientY / window.innerHeight * 100).toFixed(1);
    document.documentElement.style.setProperty('--mx', mx + '%');
    document.documentElement.style.setProperty('--my', my + '%');
  }, { passive: true });

  /* Анимированные счётчики stat-value при появлении */
  function animateCounter(el){
    var raw = el.textContent.trim();
    var match = raw.match(/^(\D*)([\d,]+)(\D*)$/);
    if (!match) return;
    var prefix = match[1], numStr = match[2].replace(/,/g,''), suffix = match[3];
    var target = parseInt(numStr, 10);
    if (isNaN(target) || target === 0) return;
    var start = 0, dur = 900, step = 16;
    var timer = setInterval(function(){
      start += step;
      var progress = Math.min(start / dur, 1);
      var ease = 1 - Math.pow(1 - progress, 3);
      var current = Math.round(target * ease);
      el.textContent = prefix + current.toLocaleString('ru') + suffix;
      if (progress >= 1) clearInterval(timer);
    }, step);
  }

  if (window.IntersectionObserver){
    var obs = new IntersectionObserver(function(entries){
      entries.forEach(function(en){
        if (en.isIntersecting){
          animateCounter(en.target);
          obs.unobserve(en.target);
        }
      });
    }, { threshold: 0.5 });
    document.querySelectorAll('.stat-value').forEach(function(el){ obs.observe(el); });
  }

  /* Ripple-эффект на кнопках */
  document.addEventListener('click', function(e){
    var btn = e.target.closest('.btn, .action-btn, .mode-btn, .main-cat-btn, .shop-buy-btn');
    if (!btn) return;
    var r = document.createElement('span');
    var rect = btn.getBoundingClientRect();
    var size = Math.max(rect.width, rect.height) * 1.4;
    r.style.cssText = [
      'position:absolute',
      'border-radius:50%',
      'pointer-events:none',
      'transform:scale(0)',
      'background:rgba(255,255,255,.22)',
      'width:' + size + 'px',
      'height:' + size + 'px',
      'left:' + (e.clientX - rect.left - size/2) + 'px',
      'top:' + (e.clientY - rect.top - size/2) + 'px',
      'animation:rippleAnim .55s cubic-bezier(.16,1,.3,1) forwards'
    ].join(';');
    if (!document.querySelector('#t73-ripple-style')){
      var st = document.createElement('style');
      st.id = 't73-ripple-style';
      st.textContent = '@keyframes rippleAnim{to{transform:scale(1);opacity:0;}}';
      document.head.appendChild(st);
    }
    btn.style.position = btn.style.position || 'relative';
    btn.style.overflow = 'hidden';
    btn.appendChild(r);
    setTimeout(function(){ if(r.parentNode) r.parentNode.removeChild(r); }, 580);
  });

  /* Перехватываем showNotification/showToast если они уже есть */
  var _orig = window.showNotification;
  window.showNotification = function(msg, type){
    if (typeof _orig === 'function') _orig.apply(this, arguments);
    window.t73Toast(msg, type === 'success' ? 'ok' : (type === 'error' ? 'err' : 'warn'));
  };

})();


