  async function callAiJudge(dataUrl, declaredTime, meta){
    var cfg = await getConfig();
    if (!cfg.apiKey) throw new Error('API ключ проверки отчётов не настроен в панели управления.');
    var instruction = await loadReportInstruction();
    var system = 'Ты проверяешь отчёты модераторов. Нельзя выдавать XP и нельзя финально принимать отчёт: ты только даёшь рекомендацию для руководства. Отвечай строго JSON без markdown: {"status":"Одобрено или Отклонено","verifiedTime":"найденное время","category":"Норма или Перенорма или Герой дня или Натяг или Не выполнено","xp":15,"reason":"короткая причина"}. Инструкция проверки: ' + instruction;
    var userText = 'Проверь отчёт по скриншоту. Заявленное время: ' + declaredTime + '\nНик: ' + (meta.nick || '') + '\nДата: ' + (meta.date || '') + '\nКомментарий: ' + (meta.work || '') + '\nВерни только JSON.';
    if (looksGemini(cfg)) return callGeminiJudge(cfg, dataUrl, system, userText);
    try {
      // Не блокируем DeepSeek/OpenRouter/другие совместимые endpoint заранее по названию модели.
      // Отправляем картинку и доверяем ответу самого API: если endpoint умеет vision, отчёт проверится.
      return await callOpenAiVisionJudge(cfg, dataUrl, system, userText);
    } catch(err) {
      var msg = err && err.message ? String(err.message) : String(err || '');
      if (/unknown variant [`']?image_url|expected [`']?text|image_url|image.*not.*support|does not support.*image|multimodal|vision|content.*string/i.test(msg)) {
        if (looksTextOnlyDeepseek(cfg)) {
          throw new Error('Указанный API отклонил изображение. Официальный DeepSeek chat/completions обычно текстовый; для отчётов нужен OpenAI-compatible endpoint с vision-моделью либо прокси, который реально принимает image_url. Если вы используете OpenRouter/другой совместимый endpoint, выберите модель с поддержкой картинок.');
        }
        throw new Error('Указанный API отклонил изображение. Для проверки отчётов нужна модель/endpoint с поддержкой image_url или input_image.');
      }
      throw err;
    }
  }
