  async function renderReview(){
    if (!(await isLeader())) { alert('Проверка отчётности доступна только руководству.'); return; }
    var area = $('reportsListArea');
    if (!area) { var form=$('reportFormArea') || document.body; form.insertAdjacentHTML('beforeend','<div id="reportsListArea"></div>'); area=$('reportsListArea'); }
    if (area.dataset.ch89StableOpen === '1') { area.dataset.ch89StableOpen='0'; area.classList.remove('ch89-stable-review-open'); area.style.display='none'; return; }
    area.dataset.ch89StableOpen='1'; area.classList.add('ch89-stable-review-open'); area.innerHTML='<div class="ch89-stable-review-card">Загружаю сданные отчёты...</div>';
    var c = client(); if (!c) { area.innerHTML='<div class="ch89-stable-review-card">База ещё не загрузилась.</div>'; return; }
    try {
      var r = await c.from('reports').select('*').order('id', { ascending:false }).limit(300);
      if (r.error) throw r.error;
      var rows = (r.data || []).filter(isReportRow);
      rows.sort(function(a,b){
        var ap = parsePayload(a), bp = parsePayload(b);
        var apend = pendingStatus(a.status) ? 1 : 0, bpend = pendingStatus(b.status) ? 1 : 0;
        if (bpend !== apend) return bpend - apend;
        return String(b.id || '').localeCompare(String(a.id || ''));
      });
      area.innerHTML = rows.length ? rows.map(cardHtml).join('') : '<div class="ch89-stable-review-card">Сданных отчётов пока нет.</div>';
    } catch(e) { area.innerHTML='<div class="ch89-stable-review-card" style="color:var(--color-error);">Ошибка загрузки: '+esc(e && e.message || e)+'</div>'; }
  }
  async function updateReportDecision(id, action){
    var c = client(), u = await authUser();
    if (!c) { alert('База ещё не загрузилась.'); return; }
    if (!(await isLeader())) { alert('Проверять отчёты может только руководство.'); return; }
    try {
      var got = await c.from('reports').select('*').eq('id', id).maybeSingle();
      if (got.error) throw got.error;
      var row = got.data; if (!row) { alert('Отчёт не найден.'); return; }
      if (u && row.email && String(row.email).toLowerCase() === String(u.email || '').toLowerCase()) { alert('Нельзя проверять свой собственный отчёт.'); return; }
      var card = document.querySelector('[data-stable-card="'+CSS.escape(id)+'"]');
      var sel = card && card.querySelector('[data-stable-norm]');
      var norm = normClean(sel && sel.value);
      var p = parsePayload(row);
      var update;
      if (action === 'reject') {
        p.finalStatus = 'Отказано'; p.finalNorm = ''; p.finalXp = 0; p.rejectedBy = u && (u.email || u.id) || ''; p.rejectedAt = new Date().toISOString();
        update = { status:'Отказано', xp:0, date:JSON.stringify(p) };
      } else {
        var xp = normXp(norm);
        p.finalStatus = norm; p.finalNorm = norm; p.finalXp = xp; p.checkedBy = u && (u.email || u.id) || ''; p.checkedAt = new Date().toISOString();
        update = { status:norm, xp:xp, date:JSON.stringify(p) };
      }
      var res = await c.from('reports').update(update).eq('id', id);
      if (res.error) throw res.error;
      var area = $('reportsListArea'); if (area) area.dataset.ch89StableOpen = '0';
      await renderReview();
      try { if (typeof window.loadReportsTable === 'function') setTimeout(function(){ window.loadReportsTable(); }, 250); } catch(e) {}
      try { if (window.T73_V94_REPORTS && typeof window.T73_V94_REPORTS.load === 'function') setTimeout(function(){ window.T73_V94_REPORTS.load(); }, 350); } catch(e) {}
    } catch(e){ alert('Ошибка сохранения решения: ' + (e && e.message ? e.message : e)); }
  }
