    return { apiKey: String(cfg.apiKey || cfg.key || '').trim(), endpoint: String(cfg.endpoint || 'https://api.deepseek.com/chat/completions').trim() || 'https://api.deepseek.com/chat/completions', model: String(cfg.model || DEFAULT_MODEL).trim() || DEFAULT_MODEL, thinking: cfg.thinking === false ? false : true };
