  function buildMessages(question){
    var messages = [{ role: 'system', content: systemPrompt() }];
    history.slice(-10).forEach(function(m){ messages.push({ role: m.role === 'assistant' ? 'assistant' : 'user', content: String(m.text || '') }); });
    messages.push({ role: 'user', content: question });
    return messages;
  }
  async function callDeepSeek(question){
    var cfg = await getConfig();
    if (!cfg.apiKey) throw new Error('AI API key не настроен. Зайдите в Панель Создателя и сохраните ключ во второй менюшке DeepSeek.');
    var payload = { model: cfg.model || DEFAULT_MODEL, messages: buildMessages(question), temperature: 0.18, max_tokens: 1200, stream: false };
    if (/^deepseek-v4-/i.test(payload.model)) { payload.thinking = { type: cfg.thinking ? 'enabled' : 'disabled' }; if (cfg.thinking) payload.thinking.reasoning_effort = 'high'; }
    var response = await fetch(cfg.endpoint, { method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + cfg.apiKey }, body: JSON.stringify(payload) });
    var data = await response.json().catch(function(){ return null; });
    if (!response.ok) { var msg = data && data.error && (data.error.message || data.error) ? (data.error.message || data.error) : ('HTTP ' + response.status); throw new Error('API: ' + msg); }
    var choice = data && data.choices && data.choices[0];
    var text = choice && choice.message && (choice.message.content || choice.message.reasoning_content);
    text = String(text || '').trim();
    if (!text) throw new Error('AI вернул пустой ответ. Попробуйте переформулировать вопрос.');
    return cleanAiText(text);
  }
  async function send(){
    if (busy) return;
    var input = $('t73AiChatInput'); if (!input) return;
    var question = String(input.value || '').trim();
    if (!question) { setStatus('Напишите вопрос по правилам модерации.', 'bad'); return; }
    busy = true;
    var btn = $('t73AiChatSendBtn'); var old = btn ? btn.textContent : '';
    if (btn) { btn.disabled = true; btn.textContent = 'Думаю...'; }
    input.value = '';
    addMessage('user', question);
    var loading = addMessage('assistant', 'Проверяю правила и подбираю ответ...', true);
    setStatus('AI анализирует вопрос по встроенной базе правил...', 'ok');
    try {
      var answer = await callDeepSeek(question);
      if (loading) { loading.classList.remove('loading'); loading.innerHTML = '<b>AI помощник:</b><br>' + formatAiAnswer(answer); }
      history.push({ role:'user', text: question });
      history.push({ role:'assistant', text: answer });
      if (history.length > 20) history = history.slice(-20);
      setStatus('Ответ готов. Для спорных ситуаций всё равно сверяйте доказательства и контекст.', 'ok');
    } catch(err) {
      var msg = err && err.message ? err.message : String(err || 'неизвестная ошибка');
      if (loading) { loading.classList.remove('loading'); loading.innerHTML = '<b>AI помощник:</b><br>' + formatAiAnswer('Не удалось получить ответ: ' + msg); }
      setStatus('Ошибка AI-чата: ' + msg, 'bad');
    } finally {
      busy = false;
      if (btn) { btn.disabled = false; btn.textContent = old || 'Отправить'; }
      scrollDown();
    }
  }
  function clearChat(){
    history = [];
    var box = messagesBox();
    if (box) box.innerHTML = '<div class="t73-ai-msg bot"><b>AI помощник:</b><br>Чат очищен. Задай новый вопрос по правилам модерации.</div>';
    setStatus('Чат очищен.', 'ok');
  }
  function bind(){
    var sendBtn = $('t73AiChatSendBtn'), clearBtn = $('t73AiChatClearBtn'), input = $('t73AiChatInput');
    if (sendBtn && sendBtn.dataset.v167Bound !== '1') { sendBtn.dataset.v167Bound = '1'; sendBtn.addEventListener('click', send); }
    if (clearBtn && clearBtn.dataset.v167Bound !== '1') { clearBtn.dataset.v167Bound = '1'; clearBtn.addEventListener('click', clearChat); }
    if (input && input.dataset.v167Bound !== '1') { input.dataset.v167Bound = '1'; input.addEventListener('keydown', function(e){ if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') { e.preventDefault(); send(); } }); }
    document.querySelectorAll('[data-ai-example]').forEach(function(btn){ if (btn.dataset.v167Bound === '1') return; btn.dataset.v167Bound = '1'; btn.addEventListener('click', function(){ var inp = $('t73AiChatInput'); if (inp) { inp.value = btn.getAttribute('data-ai-example') || ''; inp.focus(); } }); });
  }
  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', bind); else bind();
