/* === extracted script: ch89-final-safe-script === */
(function(){
  'use strict';
  if (window.__CH89_FINAL_SAFE_PATCH__) return;
  window.__CH89_FINAL_SAFE_PATCH__ = true;

  var SERVER_NAME = 'Cherepovets 89';
  var ROOT_PATH = '/';
  var HELP_PATH = '/help';
  var $ = function(id){ return document.getElementById(id); };
  var qsa = function(sel, root){ return Array.prototype.slice.call((root || document).querySelectorAll(sel)); };

  function setImportant(el, prop, value){
    if (el && el.style && el.style.setProperty) el.style.setProperty(prop, value, 'important');
  }

  function renameVisibleText(){
    var brand = document.querySelector('.brand-title');
    if (brand) brand.textContent = SERVER_NAME;
    qsa('title, meta[property="og:title"], meta[property="og:description"]').forEach(function(el){
      if (el.tagName === 'TITLE') el.textContent = (el.textContent || '').replace(/Tambov\s*73/gi, SERVER_NAME);
      if (el.content) el.content = el.content.replace(/Tambov\s*73/gi, SERVER_NAME);
    });
  }

  function currentCat(){
    var active = document.querySelector('.main-cat-btn.active[data-cat]');
    var cat = active && active.dataset ? active.dataset.cat : 'moderation';
    if (cat !== 'general' && cat !== 'moderation') cat = 'moderation';
    return cat;
  }

  function setActiveCategory(cat){
    if (cat !== 'general') cat = 'moderation';
    qsa('.main-cat-btn[data-cat]').forEach(function(btn){
      var ok = btn.dataset.cat === cat;
      btn.classList.toggle('active', ok);
    });
    ['support','organizations'].forEach(function(name){
      var b = document.querySelector('.main-cat-btn[data-cat="' + name + '"]');
      if (b) { setImportant(b, 'display', 'none'); b.classList.remove('active'); b.setAttribute('aria-hidden','true'); }
    });
  }

  function syncNav(cat){
    cat = cat || currentCat();
    setActiveCategory(cat);
    var mod = $('subNavModeration');
    var gen = $('subNavGeneral');
    var sup = $('subNavSupport');
    var org = $('subNavOrganizations');
    [sup, org, $('gossOrgActionNav'), $('gossOrgActionNavV3'), $('gossOrgActionNavV4')].forEach(function(el){
      if (!el) return;
      el.classList.remove('t73-v44-active-subnav');
      setImportant(el, 'display', 'none');
      setImportant(el, 'visibility', 'hidden');
      setImportant(el, 'pointer-events', 'none');
    });
    if (mod) {
      mod.classList.toggle('t73-v44-active-subnav', cat === 'moderation');
      setImportant(mod, 'display', cat === 'moderation' ? 'flex' : 'none');
      setImportant(mod, 'visibility', cat === 'moderation' ? 'visible' : 'hidden');
      setImportant(mod, 'pointer-events', cat === 'moderation' ? 'auto' : 'none');
    }
    if (gen) {
      gen.classList.toggle('t73-v44-active-subnav', cat === 'general');
      setImportant(gen, 'display', cat === 'general' ? 'flex' : 'none');
      setImportant(gen, 'visibility', cat === 'general' ? 'visible' : 'hidden');
      setImportant(gen, 'pointer-events', cat === 'general' ? 'auto' : 'none');
      var reports = $('reportsTableBtn');
      if (reports && gen.contains(reports)) {
        reports.textContent = '📊 Таблица отчётов';
        reports.dataset.mode = 'reports_table';
        setImportant(reports, 'display', 'inline-flex');
        setImportant(reports, 'visibility', 'visible');
        setImportant(reports, 'pointer-events', 'auto');
      }
    }
  }

  function hideAllModeSections(){
    qsa('[id^="mode-"]').forEach(function(sec){
      if (sec.id !== 'mode-instructia') setImportant(sec, 'display', 'none');
    });
  }

  function openInstruction(push){
    document.body.classList.add('t73-route-instructia');
    document.documentElement.setAttribute('data-site-theme', 'guide');
    hideAllModeSections();
    var game = $('game');
    var instr = $('mode-instructia');
    if (game) setImportant(game, 'display', 'none');
    if (instr) {
      setImportant(instr, 'display', 'block');
      instr.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
    qsa('.main-cat-btn').forEach(function(b){ b.classList.remove('active'); });
    var ib = $('openInstructiaBtn');
    if (ib) ib.classList.add('active');
    if (push && location.pathname !== HELP_PATH) history.pushState({ch89:'help'}, '', HELP_PATH);
  }

  function closeInstruction(push){
    document.body.classList.remove('t73-route-instructia');
    var game = $('game');
    if (game) setImportant(game, 'display', 'grid');
    var instr = $('mode-instructia');
    if (instr) setImportant(instr, 'display', 'none');
    syncNav('moderation');
    if (typeof window.switchMode === 'function') {
      var btn = document.querySelector('#subNavModeration .mode-btn[data-mode="moderation"]');
      try { window.switchMode('moderation', btn); } catch(e) {}
    }
    if (push && location.pathname === HELP_PATH) history.pushState({ch89:'root'}, '', ROOT_PATH);
  }

  function bind(){
    renameVisibleText();
    qsa('.main-cat-btn[data-cat="support"], .main-cat-btn[data-cat="organizations"]').forEach(function(btn){
      setImportant(btn, 'display', 'none');
      btn.setAttribute('aria-hidden','true');
      btn.onclick = function(e){ e.preventDefault(); e.stopPropagation(); return false; };
    });
    qsa('.main-cat-btn[data-cat="moderation"], .main-cat-btn[data-cat="general"]').forEach(function(btn){
      if (btn.dataset.ch89Bound === '1') return;
      btn.dataset.ch89Bound = '1';
      btn.addEventListener('click', function(){
        setTimeout(function(){ syncNav(btn.dataset.cat); }, 0);
        setTimeout(function(){ syncNav(btn.dataset.cat); }, 80);
      }, true);
    });
    var inst = $('openInstructiaBtn');
    if (inst && inst.dataset.ch89Bound !== '1') {
      inst.dataset.ch89Bound = '1';
      inst.addEventListener('click', function(e){ e.preventDefault(); e.stopPropagation(); openInstruction(true); }, true);
    }
    var back = $('instructiaBackBtn');
    if (back && back.dataset.ch89Bound !== '1') {
      back.dataset.ch89Bound = '1';
      back.addEventListener('click', function(e){ e.preventDefault(); closeInstruction(true); }, true);
    }
    if (location.pathname === HELP_PATH || location.pathname.replace(/\/$/,'') === HELP_PATH) openInstruction(false);
    else syncNav(currentCat());
  }

  var oldSwitch = window.switchMode;
  window.switchMode = function(mode, btn){
    if (mode === 'instructia') { openInstruction(true); return; }
    document.body.classList.remove('t73-route-instructia');
    var out;
    if (typeof oldSwitch === 'function') out = oldSwitch.apply(this, arguments);
    setTimeout(function(){ syncNav(currentCat()); }, 20);
    setTimeout(function(){ syncNav(currentCat()); }, 120);
    return out;
  };

  window.addEventListener('popstate', function(){
    if (location.pathname === HELP_PATH || location.pathname.replace(/\/$/,'') === HELP_PATH) openInstruction(false);
    else closeInstruction(false);
  });

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', bind);
  else bind();
  [150, 500, 1200, 2500].forEach(function(ms){ setTimeout(bind, ms); });
  var obsTimer = null;
  try {
    new MutationObserver(function(){ clearTimeout(obsTimer); obsTimer = setTimeout(bind, 160); }).observe(document.documentElement, { childList:true, subtree:true });
  } catch(e) {}
})();


