/* === CH89 V11: post-auth visible app guard === */
(function(){
  'use strict';
  if (window.__CH89_V11_AUTH_VISIBLE_GUARD__) return;
  window.__CH89_V11_AUTH_VISIBLE_GUARD__ = true;

  function $(id){ return document.getElementById(id); }
  function qsa(sel){ return Array.prototype.slice.call(document.querySelectorAll(sel)); }

  function getClient(){
    try { if (window.supa && window.supa.auth) return window.supa; } catch(e) {}
    try { if (window.__T73_SUPA && window.__T73_SUPA.auth) return window.__T73_SUPA; } catch(e) {}
    try { if (window.t73Supa && window.t73Supa.auth) return window.t73Supa; } catch(e) {}
    try { if (window.supabaseClient && window.supabaseClient.auth) return window.supabaseClient; } catch(e) {}
    try {
      if (window.supabase && typeof window.supabase.createClient === 'function') {
        window.__T73_SUPA = window.supabase.createClient('https://zisjpdugogkntsmkvlha.supabase.co', 'sb_publishable_0q1B_GyskY1umJO7T-mTIQ_LkL9ncr_');
        window.supa = window.__T73_SUPA;
        return window.__T73_SUPA;
      }
    } catch(e) {}
    return null;
  }

  function hasStoredSession(){
    try {
      for (var i = 0; i < localStorage.length; i++) {
        var key = localStorage.key(i) || '';
        if (!/^sb-.*-auth-token$/.test(key)) continue;
        var raw = localStorage.getItem(key) || '';
        if (/access_token|refresh_token|expires_at/.test(raw)) return true;
      }
    } catch(e) {}
    return false;
  }

  function show(el, display){
    if (!el) return;
    el.style.removeProperty('display');
    el.style.setProperty('visibility', 'visible', 'important');
    el.style.setProperty('opacity', '1', 'important');
    if (display) el.style.setProperty('display', display, 'important');
  }

  function ensureDefaultMode(){
    var page = document.querySelector('.page');
    show(page, 'block');
    show(document.querySelector('.topbar'));
    show($('infoBanner'));
    show(document.querySelector('.hero'));
    show(document.querySelector('.nav-container'));
    show($('game'));

    var anyVisiblePanel = qsa('#game > .panel, #game > .game-card').some(function(el){
      var s = getComputedStyle(el);
      var r = el.getBoundingClientRect();
      return el.id !== 'mode-instructia' && s.display !== 'none' && s.visibility !== 'hidden' && Number(s.opacity) !== 0 && r.width > 0 && r.height > 0;
    });
    if (!anyVisiblePanel) {
      var mod = $('mode-moderation');
      if (mod) {
        mod.style.removeProperty('display');
        mod.style.setProperty('display', 'block', 'important');
        mod.style.setProperty('visibility', 'visible', 'important');
        mod.style.setProperty('opacity', '1', 'important');
      }
      qsa('#game > .panel, #game > .game-card').forEach(function(el){
        if (el.id && el.id !== 'mode-moderation' && !el.classList.contains('side')) {
          el.style.setProperty('display', 'none', 'important');
        }
      });
    }

    var modCat = document.querySelector('.main-cat-btn[data-cat="moderation"]');
    if (modCat && !document.querySelector('.main-cat-btn.active')) modCat.classList.add('active');
    var modNav = $('subNavModeration');
    if (modNav) {
      modNav.style.setProperty('display', 'flex', 'important');
      modNav.style.setProperty('visibility', 'visible', 'important');
      modNav.style.setProperty('opacity', '1', 'important');
    }
  }

  function openApp(reason){
    if (!document.body) return;
    document.documentElement.classList.add('ch89-main-visible');
    document.body.classList.add('ch89-main-visible');
    document.body.classList.add('ch89-auth-ready');
    document.body.classList.remove('ch89-auth-lock');
    document.body.classList.remove('ch89-session-checking');
    document.body.style.overflow = '';

    var gate = $('ch89EntryAuthGate');
    if (gate) {
      gate.hidden = true;
      gate.setAttribute('aria-hidden', 'true');
      gate.style.setProperty('display', 'none', 'important');
      gate.style.setProperty('visibility', 'hidden', 'important');
      gate.style.setProperty('opacity', '0', 'important');
      gate.style.setProperty('pointer-events', 'none', 'important');
    }
    var oldModal = $('authModal');
    if (oldModal) oldModal.style.setProperty('display', 'none', 'important');

    ensureDefaultMode();
    window.__CH89_V11_LAST_OPEN_REASON__ = reason || 'auth-visible-guard';
    try { window.dispatchEvent(new CustomEvent('ch89:app-visible', { detail: { reason: window.__CH89_V11_LAST_OPEN_REASON__ } })); } catch(e) {}
  }

  function withTimeout(promise, ms){
    return Promise.race([
      promise,
      new Promise(function(resolve){ setTimeout(function(){ resolve({ __timeout: true }); }, ms); })
    ]);
  }

  async function checkAndOpen(reason){
    var c = getClient();
    if (c && c.auth && typeof c.auth.getSession === 'function') {
      try {
        var res = await withTimeout(c.auth.getSession(), 2600);
        var user = res && res.data && res.data.session && res.data.session.user;
        if (user) {
          window.currentUser = user;
          openApp(reason || 'supabase-session');
          return true;
        }
      } catch(e) {}
    }
    if (hasStoredSession()) {
      openApp(reason || 'stored-supabase-token');
      return true;
    }
    return false;
  }

  function boot(){
    // Проверяем несколько раз: CDN Supabase и localStorage могут появиться не одновременно.
    checkAndOpen('boot');
    setTimeout(function(){ checkAndOpen('t800'); }, 800);
    setTimeout(function(){ checkAndOpen('t2200'); }, 2200);
    setTimeout(function(){ checkAndOpen('t4500'); }, 4500);

    // Если класс ready уже поставил старый auth-patch, просто раскрываем интерфейс.
    setTimeout(function(){
      if (document.body && document.body.classList.contains('ch89-auth-ready')) openApp('existing-ready-class');
    }, 1200);

    var c = getClient();
    try {
      if (c && c.auth && typeof c.auth.onAuthStateChange === 'function') {
        c.auth.onAuthStateChange(function(event, session){
          if (session && session.user) {
            window.currentUser = session.user;
            openApp('auth-state-' + event);
          }
        });
      }
    } catch(e) {}
  }

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', boot, { once: true });
  else boot();

  window.CH89_V11_FORCE_OPEN_APP = openApp;
})();
